 75→// ExecuteResult holds the output of running an instrumented function.
 76→type ExecuteResult struct {
 77→	ReturnValue   json.RawMessage   `json:"return_value,omitempty"`
 78→	ThrownError   *ErrorInfo        `json:"thrown_error,omitempty"`
 79→	BranchPath    []BranchDecision  `json:"branch_path"`
 80→	LinesExecuted []int             `json:"lines_executed"`
 81→	ExternalCalls []ExternalCall    `json:"external_calls,omitempty"`
 82→	SideEffects   []SideEffect      `json:"side_effects"`
 83→	ScopeEvents   []json.RawMessage `json:"scope_events"`
 84→	Performance   PerfMetrics       `json:"performance"`
 85→}
