242→func (h *Handler) handleExecute(resp Response, req Request) Response {
243→	file := req.File
244→	if file == "" {
245→		file = h.lastAnalyzedFile
246→	}
247→	if file == "" {
248→		resp.Status = "error"
249→		resp.Code = ErrInvalidRequest
250→		resp.Message = "execute command requires a file path (or a prior analyze)"
251→		return resp
252→	}
253→
254→	if req.Function == nil || *req.Function == "" {
255→		resp.Status = "error"
256→		resp.Code = ErrInvalidRequest
257→		resp.Message = "execute command requires a function name"
258→		return resp
259→	}
260→
261→	if _, err := os.Stat(file); err != nil {
262→		resp.Status = "error"
263→		resp.Code = ErrFileNotFound
264→		resp.Message = fmt.Sprintf("file not found: %s", file)
265→		return resp
266→	}
267→
268→	// Convert protocol MockConfigs to instrument MockConfigs and pass to executor.
269→	var execMocks []instrument.MockConfig
270→	for _, m := range req.Mocks {
271→		execMocks = append(execMocks, instrument.MockConfig{
272→			Symbol:           m.Symbol,
273→			ReturnValues:     m.ReturnValues,
274→			ShouldTrackCalls: m.ShouldTrackCalls,
275→			DefaultBehavior:  m.DefaultBehavior,
276→		})
277→	}
278→	result, err := instrument.ExecuteFunction(file, *req.Function, req.Inputs, execMocks)
279→	if err != nil {
280→		resp.Status = "error"
281→		if strings.Contains(err.Error(), "function not found") {
282→			resp.Code = ErrFunctionNotFound
283→		} else if strings.Contains(err.Error(), "build failed") {
284→			resp.Code = ErrInstrumentationFailed
285→		} else if strings.Contains(err.Error(), "timed out") {
286→			resp.Code = ErrExecutionTimeout
287→		} else {
288→			resp.Code = ErrInternalError
289→		}
290→		resp.Message = err.Error()
291→		return resp
292→	}
293→
294→	resp.Status = "execute"
295→	resp.ReturnValue = result.ReturnValue
296→	resp.ThrownError = convertErrorInfo(result.ThrownError)
297→	resp.LinesExecuted = toIntSlice(result.LinesExecuted)
298→	resp.BranchPath = convertBranchPath(result.BranchPath)
299→	resp.PathConstraints = extractPathConstraints(result.BranchPath)
300→	resp.CallsToExternal = convertExternalCalls(result.ExternalCalls)
301→	resp.SideEffects = convertSideEffects(result.SideEffects)
302→	resp.ScopeEvents = result.ScopeEvents
303→	resp.Performance = &PerfMetrics{
304→		WallTimeMs:         result.Performance.WallTimeMs,
305→		CPUTimeUs:          result.Performance.CPUTimeUs,
306→		HeapUsedBytes:      result.Performance.HeapUsedBytes,
307→		HeapAllocatedBytes: result.Performance.HeapAllocatedBytes,
308→	}
309→
310→	return resp
311→}
