467→func (h *Handler) handleTeardown(resp Response, req Request) Response {
468→	if req.Scope == "" {
469→		resp.Status = "error"
470→		resp.Code = ErrInvalidRequest
471→		resp.Message = "teardown command requires a scope"
472→		return resp
473→	}
474→	if !req.Level.IsValid() {
475→		resp.Status = "error"
476→		resp.Code = ErrInvalidRequest
477→		resp.Message = fmt.Sprintf("teardown command requires a valid level, got %q", req.Level)
478→		return resp
479→	}
480→
481→	h.log.Debug("Running teardown", "scope", req.Scope, "level", req.Level)
482→
483→	found := h.setupLoader.Teardown(req.Scope, string(req.Level))
484→	if !found {
485→		resp.Status = "error"
486→		resp.Code = ErrInternalError
487→		resp.Message = fmt.Sprintf("No setup context found for %s:%s. Call setup first.", req.Level, req.Scope)
488→		return resp
489→	}
490→
491→	// Clear stale session state so the next setup/execute cycle starts clean.
492→	h.lastAnalyzedFile = ""
493→	h.registry.Handles.Clear()
494→
495→	resp.Status = "teardown_ack"
496→	return resp
497→}
