499→func (h *Handler) handleGenerate(resp Response, req Request) Response {
500→	if req.File == "" {
501→		resp.Status = "error"
502→		resp.Code = ErrInvalidRequest
503→		resp.Message = "generate command requires a file path"
504→		return resp
505→	}
506→	if req.Name == "" {
507→		resp.Status = "error"
508→		resp.Code = ErrInvalidRequest
509→		resp.Message = "generate command requires a name"
510→		return resp
511→	}
512→
513→	var recipe json.RawMessage
514→	if req.Recipe != nil {
515→		recipe = *req.Recipe
516→	}
517→
518→	value, generatorID, outRecipe, err := h.registry.Generate(req.File, req.Name, recipe)
519→	if err != nil {
520→		resp.Status = "error"
521→		resp.Code = ErrInternalError
522→		resp.Message = fmt.Sprintf("generate failed: %v", err)
523→		return resp
524→	}
525→
526→	resp.Status = "generate"
527→	valCopy := json.RawMessage(value)
528→	resp.Value = &valCopy
529→	resp.GeneratorID = generatorID
530→	if outRecipe != nil {
531→		recipeCopy := json.RawMessage(outRecipe)
532→		resp.Recipe = &recipeCopy
533→	}
534→	return resp
535→}
