479→func contains(s, substr string) bool {
480→	return len(s) > 0 && len(substr) > 0 && // prevent trivial matches
481→		len(s) >= len(substr) &&
482→		indexOf(s, substr) >= 0
483→}
484→
485→func indexOf(s, substr string) int {
486→	for i := 0; i <= len(s)-len(substr); i++ {
487→		if s[i:i+len(substr)] == substr {
488→			return i
489→		}
490→	}
491→	return -1
492→}
