  16→// reqJSON builds a JSON request string using ProtocolVersion instead of a
  17→// hard-coded version literal.
  18→func reqJSON(id int, command string, extra ...string) string {
  19→	base := fmt.Sprintf(`{"protocol_version":%q,"id":%d,"command":%q`, ProtocolVersion, id, command)
  20→	for _, e := range extra {
  21→		base += "," + e
  22→	}
  23→	return base + "}"
  24→}
  25→
  26→// sendRecv sends a single request and reads the response.
  27→func sendRecv(t *testing.T, reqJSON string) Response {
  28→	t.Helper()
  29→	input := strings.NewReader(reqJSON + "\n")
  30→	var output bytes.Buffer
  31→	handler := NewHandler(input, &output, io.Discard)
  32→	if err := handler.Run(); err != nil {
  33→		t.Fatalf("handler.Run: %v", err)
  34→	}
  35→	lines := strings.Split(strings.TrimSpace(output.String()), "\n")
  36→	if len(lines) == 0 {
  37→		t.Fatal("no response received")
  38→	}
  39→	var resp Response
  40→	if err := json.Unmarshal([]byte(lines[0]), &resp); err != nil {
  41→		t.Fatalf("unmarshal response: %v (raw: %s)", err, lines[0])
  42→	}
  43→	return resp
  44→}
  45→
  46→// conversation sends multiple requests (one per line) and returns all responses.
  47→func conversation(t *testing.T, requests ...string) []Response {
  48→	t.Helper()
  49→	input := strings.NewReader(strings.Join(requests, "\n") + "\n")
  50→	var output bytes.Buffer
  51→	handler := NewHandler(input, &output, io.Discard)
  52→	if err := handler.Run(); err != nil {
  53→		t.Fatalf("handler.Run: %v", err)
  54→	}
  55→	lines := strings.Split(strings.TrimSpace(output.String()), "\n")
  56→	var responses []Response
  57→	for _, line := range lines {
  58→		if line == "" {
  59→			continue
  60→		}
  61→		var resp Response
  62→		if err := json.Unmarshal([]byte(line), &resp); err != nil {
  63→			t.Fatalf("unmarshal response: %v (raw: %s)", err, line)
  64→		}
  65→		responses = append(responses, resp)
  66→	}
  67→	return responses
  68→}
