1076→// TestConvertSideEffects verifies that instrument.SideEffect values are
1077→// correctly mapped to protocol SideEffect values with the right JSON field
1078→// names (kind, not type) and snake_case values (console_output, not ConsoleOutput).
1079→// TestExecuteAfterInstrumentWithoutAnalyze verifies the scan flow:
1080→// Instrument (with file) → Execute (without file) succeeds because
1081→// handleInstrument sets lastAnalyzedFile.
1082→func TestExecuteAfterInstrumentWithoutAnalyze(t *testing.T) {
1083→	tmp := filepath.Join(t.TempDir(), "target.go")
1084→	src := `package main
1085→
1086→func double(x int) int {
1087→	return x * 2
1088→}
1089→`
1090→	if err := os.WriteFile(tmp, []byte(src), 0644); err != nil {
1091→		t.Fatal(err)
1092→	}
1093→	responses := conversation(t,
1094→		reqJSON(1, "handshake", `"capabilities":["instrument","execute"]`),
1095→		reqJSON(2, "instrument", fmt.Sprintf(`"file":"%s","function":"double"`, tmp)),
1096→		reqJSON(3, "execute", `"function":"double","inputs":[5],"mocks":[]`),
1097→		reqJSON(4, "shutdown"),
1098→	)
1099→	if len(responses) != 4 {
1100→		t.Fatalf("got %d responses, want 4", len(responses))
1101→	}
1102→	if responses[1].Status != "instrument" {
1103→		t.Fatalf("instrument: status = %q, want instrument (message: %s)", responses[1].Status, responses[1].Message)
1104→	}
1105→	if responses[2].Status != "execute" {
1106→		t.Fatalf("execute: status = %q, want execute (message: %s)", responses[2].Status, responses[2].Message)
1107→	}
1108→	var retVal int
1109→	if err := json.Unmarshal(responses[2].ReturnValue, &retVal); err != nil {
1110→		t.Fatalf("parsing return value: %v", err)
1111→	}
1112→	if retVal != 10 {
1113→		t.Errorf("expected return value 10, got %d", retVal)
1114→	}
1115→	// Cleanup instrumented output
1116→	if responses[1].OutputFile != nil {
1117→		os.RemoveAll(*responses[1].OutputFile)
1118→	}
1119→}
