  1→/**
  2→ * Protocol types for communication between the Rust core and TypeScript frontend.
  3→ *
  4→ * All messages are newline-delimited JSON over stdin/stdout. The core sends
  5→ * Request messages and receives Response messages back. Every message includes
  6→ * a protocol version for compatibility checking.
  7→ */
  8→
  9→export const PROTOCOL_VERSION = "0.1.0";
 10→export const FRONTEND_LANGUAGE = "typescript";
 11→
 12→// ---------------------------------------------------------------------------
 13→// Request: Core → Frontend
 14→// ---------------------------------------------------------------------------
 15→
 16→export type SetupMode = "per_function" | "per_execution";
 17→
 18→export type SetupLevel = "session" | "file" | "function" | "execution";
 19→
 20→export interface SetupContextEntry {
 21→  level: SetupLevel;
 22→  context: unknown;
 23→}
 24→
 25→export interface SetupContextStack {
 26→  contexts: SetupContextEntry[];
 27→}
 28→
 29→export type GeneratorKind = "type_name" | "param_name";
 30→
 31→export type Command =
 32→  | "handshake"
 33→  | "analyze"
 34→  | "instrument"
 35→  | "execute"
 36→  | "setup"
 37→  | "teardown"
 38→  | "generate"
 39→  | "shutdown";
 40→
 41→export interface MockConfig {
 42→  symbol: string;
 43→  return_values: unknown[];
 44→  should_track_calls: boolean;
 45→  default_behavior: "return_generated" | "repeat_last" | "throw_error" | "passthrough";
 46→}
 47→
 48→interface BaseRequest {
 49→  protocol_version: string;
 50→  id: number;
 51→  command: Command;
 52→}
 53→
 54→export interface HandshakeRequest extends BaseRequest {
 55→  command: "handshake";
 56→  capabilities: string[];
 57→}
 58→
 59→export interface AnalyzeRequest extends BaseRequest {
 60→  command: "analyze";
 61→  file: string;
 62→  function?: string | null;
 63→  project_root?: string | null;
 64→}
 65→
 66→export interface InstrumentRequest extends BaseRequest {
 67→  command: "instrument";
 68→  file: string;
 69→  function: string;
 70→  mocks: MockConfig[];
 71→  project_root?: string | null;
 72→}
 73→
 74→export interface ExecuteRequest extends BaseRequest {
 75→  command: "execute";
 76→  function: string;
 77→  inputs: unknown[];
 78→  mocks: MockConfig[];
 79→  setup_context?: SetupContextStack | null;
 80→}
 81→
 82→export interface SetupRequest extends BaseRequest {
 83→  command: "setup";
 84→  file: string;
 85→  scope: string;
 86→  level: SetupLevel;
 87→  parent_context?: SetupContextStack | null;
 88→  project_root?: string | null;
 89→}
 90→
 91→export interface TeardownRequest extends BaseRequest {
 92→  command: "teardown";
 93→  scope: string;
 94→  level: SetupLevel;
 95→}
 96→
 97→export interface GenerateRequest extends BaseRequest {
 98→  command: "generate";
 99→  file: string;
100→  name: string;
101→  kind: GeneratorKind;
102→  recipe?: unknown;
103→  project_root?: string | null;
104→}
105→
106→export interface ShutdownRequest extends BaseRequest {
107→  command: "shutdown";
108→}
109→
110→export type Request =
111→  | HandshakeRequest
112→  | AnalyzeRequest
113→  | InstrumentRequest
114→  | ExecuteRequest
115→  | SetupRequest
116→  | TeardownRequest
117→  | GenerateRequest
118→  | ShutdownRequest;
119→
120→// ---------------------------------------------------------------------------
121→// Response: Frontend → Core
122→// ---------------------------------------------------------------------------
123→
124→export type ResponseStatus =
125→  | "handshake"
126→  | "analyze"
127→  | "instrument"
128→  | "execute"
129→  | "setup"
130→  | "teardown_ack"
131→  | "generate"
132→  | "shutdown_ack"
133→  | "error";
134→
135→/** Canonical error codes matching protocol/registry.yaml (11 codes). */
136→export const ALL_ERROR_CODES = [
137→  "file_not_found",
138→  "function_not_found",
139→  "parse_error",
140→  "instrumentation_failed",
141→  "execution_timeout",
142→  "execution_crash",
143→  "version_mismatch",
144→  "invalid_request",
145→  "compilation_error",
146→  "internal_error",
147→  "not_supported",
148→] as const;
149→
150→export type ErrorCode = (typeof ALL_ERROR_CODES)[number];
151→
152→interface BaseResponse {
153→  protocol_version: string;
154→  id: number;
155→  status: ResponseStatus;
156→}
157→
158→export interface HandshakeResponse extends BaseResponse {
159→  status: "handshake";
160→  frontend_version: string;
161→  language: string;
162→  capabilities: string[];
163→}
164→
165→export interface AnalyzeResponse extends BaseResponse {
166→  status: "analyze";
167→  functions: FunctionAnalysis[];
168→}
169→
170→export interface InstrumentResponse extends BaseResponse {
171→  status: "instrument";
172→  instrumented: boolean;
173→  output_file: string | null;
174→  instrumentable_line_count?: number;
175→}
176→
177→export interface ExecuteResponse extends BaseResponse {
178→  status: "execute";
179→  return_value: unknown;
180→  thrown_error: ErrorInfo | null;
181→  branch_path: BranchDecision[];
182→  lines_executed: number[];
183→  calls_to_external: ExternalCall[];
184→  path_constraints: SymConstraint[];
185→  side_effects: SideEffect[];
186→  performance: PerformanceMetrics;
187→  capture_truncation?: TruncationInfo;
188→  scope_events?: TraceEvent[];
189→  discovered_dependencies?: DiscoveredDependency[];
190→}
191→
192→export interface SetupResponse extends BaseResponse {
193→  status: "setup";
194→  setup_context: unknown;
195→}
196→
197→export interface TeardownAckResponse extends BaseResponse {
198→  status: "teardown_ack";
199→}
200→
201→export interface GenerateResponse extends BaseResponse {
202→  status: "generate";
203→  value: unknown;
204→  generator_id: string;
205→  recipe?: unknown;
206→}
207→
208→export interface ShutdownAckResponse extends BaseResponse {
209→  status: "shutdown_ack";
210→}
211→
212→export interface ErrorResponse extends BaseResponse {
213→  status: "error";
214→  code: ErrorCode;
215→  message: string;
216→  details?: unknown;
217→}
218→
219→export type Response =
220→  | HandshakeResponse
221→  | AnalyzeResponse
222→  | InstrumentResponse
223→  | ExecuteResponse
224→  | SetupResponse
225→  | TeardownAckResponse
226→  | GenerateResponse
227→  | ShutdownAckResponse
228→  | ErrorResponse;
