231→// Supporting types
232→// ---------------------------------------------------------------------------
233→
234→/** A literal constant extracted from source code for use as a candidate test input. */
235→export type LiteralValue =
236→  | { type: "int"; value: number }
237→  | { type: "float"; value: number }
238→  | { type: "str"; value: string }
239→  | { type: "bool"; value: boolean }
240→  | { type: "regex"; pattern: string };
