264→export interface ParamInfo {
265→  name: string;
266→  type: TypeInfo;
267→  type_name?: string;
268→}
269→
270→/** Well-known complex types beyond primitives and structural types. */
271→export type ComplexKind =
272→  | "date" | "date_time" | "time" | "duration"
273→  | "reg_exp" | "char" | "symbol"
274→  | "big_int" | "big_decimal" | "complex" | "rational" | "range"
275→  | "buffer" | "bit_set"
276→  | "error" | "option" | "result"
277→  | "closure" | "iterator"
278→  | "url" | "ip_address"
279→  | "uuid"
280→  | "path"
281→  | "money" | "sem_ver" | "email" | "mime_type" | "color" | "geo_point" | "locale"
282→  | "rune" | "go_byte";
283→
284→export type TypeInfo =
285→  | { kind: "int" }
286→  | { kind: "float" }
287→  | { kind: "str" }
288→  | { kind: "bool" }
289→  | { kind: "unknown" }
290→  | { kind: "array"; element: TypeInfo }
291→  | { kind: "object"; fields: [string, TypeInfo][] }
292→  | { kind: "union"; variants: TypeInfo[] }
293→  | { kind: "nullable"; inner: TypeInfo }
294→  | { kind: "complex"; complex_kind: ComplexKind; metadata?: Record<string, unknown>; inner?: TypeInfo }
295→  | { kind: "opaque"; label: string };
