315→export type SymExpr =
316→  | { kind: "param"; name: string; path: string[] }
317→  | SymExprConst
318→  | { kind: "bin_op"; op: BinOpKind; left: SymExpr; right: SymExpr }
319→  | { kind: "un_op"; op: UnOpKind; operand: SymExpr }
320→  | { kind: "call"; name: string; receiver: SymExpr | null; args: SymExpr[] }
321→  | { kind: "unknown" };
322→
323→/** Const variant of SymExpr. Flattened to match Rust serde serialization. */
324→export type SymExprConst =
325→  | { kind: "const"; type: "int"; value: number }
326→  | { kind: "const"; type: "float"; value: number }
327→  | { kind: "const"; type: "str"; value: string }
328→  | { kind: "const"; type: "bool"; value: boolean }
329→  | { kind: "const"; type: "null" }
330→  | { kind: "const"; type: "undefined" }
