  1→/**
  2→ * Function executor for the Shatter TypeScript frontend.
  3→ *
  4→ * Compiles TypeScript source to JavaScript, executes the target function
  5→ * with provided inputs in a sandboxed context, and returns the result
  6→ * with performance metrics and (for instrumented code) branch decisions.
  7→ */
  8→
  9→import * as ts from "typescript";
 10→import * as fs from "node:fs";
 11→import * as vm from "node:vm";
 12→import * as path from "node:path";
 13→import { createRequire } from "node:module";
 14→import { reconstructValue } from "./reconstruct.js";
 15→import type {
 16→  ExecuteResponse,
 17→  ErrorInfo,
 18→  ErrorCategory,
 19→  PerformanceMetrics,
 20→  BranchDecision,
 21→  SymConstraint,
 22→  SymExpr,
 23→  SideEffect,
 24→  TruncationInfo,
 25→  TraceEvent,
 26→  ScopeEvent,
 27→  DiscoveredDependency,
 28→} from "./protocol.js";
 29→import { RECORD_FUNCTION, BRANCH_FUNCTION, SCOPE_EVENT_FUNCTION, MOCK_REGISTRY, MOCK_CALL_FUNCTION } from "./instrumentor.js";
 30→import type { MockConfig, ExternalCall } from "./protocol.js";
 31→import { REACT_MODULE_NAMES, getReactShim } from "./react-shim.js";
 32→
 33→export const DEFAULT_EXEC_TIMEOUT_MS = 15_000;
 34→
 35→/** Default number of head console lines to keep before truncation. */
 36→export const CAPTURE_HEAD_LINES = 50;
 37→/** Default number of tail console lines to keep after truncation. */
 38→export const CAPTURE_TAIL_LINES = 20;
 39→/** Maximum total bytes for captured console output before truncation. */
 40→export const CAPTURE_MAX_BYTES = 6144;
 41→/** Maximum bytes for a single side-effect message. */
 42→export const MESSAGE_MAX_BYTES = 4096;
 43→
 44→/**
 45→ * Read SHATTER_EXEC_TIMEOUT env var (seconds) and return milliseconds.
 46→ * Default: 15s. Ignores non-positive or non-numeric values.
 47→ */
 48→export function getExecTimeoutMs(): number {
 49→  const raw = process.env["SHATTER_EXEC_TIMEOUT"];
 50→  if (raw !== undefined) {
 51→    const secs = parseFloat(raw);
 52→    if (Number.isFinite(secs) && secs > 0) {
 53→      return secs * 1000;
 54→    }
 55→  }
 56→  return DEFAULT_EXEC_TIMEOUT_MS;
 57→}
 58→
 59→/** Module names that spawn subprocesses — require() calls to these are flagged. */
 60→const SUBPROCESS_MODULES = new Set([
 61→  "child_process", "node:child_process",
 62→]);
 63→
 64→/** Symbols within child_process that spawn subprocesses. */
 65→const SUBPROCESS_SYMBOLS = new Set([
 66→  "exec", "execSync", "execFile", "execFileSync",
 67→  "spawn", "spawnSync", "fork",
 68→]);
 69→
 70→const VALIDATION_ERROR_PATTERNS = /Validation|Invalid|BadRequest|Forbidden|Unauthorized|NotFound/i;
 71→const RUNTIME_ERROR_TYPES = new Set(["TypeError", "ReferenceError", "SyntaxError", "RangeError", "URIError"]);
 72→
 73→/**
 74→ * Classify an error into a structured category using language-level signals.
 75→ * - validation: custom error subclasses or names suggesting deliberate input rejection
 76→ * - runtime: JS built-in error types indicating accidental failures
 77→ * - infrastructure: timeouts and system-level failures
 78→ */
 79→export function classifyError(errorType: string, message: string): ErrorCategory {
 80→  if (/timed?\s*out/i.test(message) || errorType === "ERR_SCRIPT_EXECUTION_TIMEOUT") {
 81→    return "infrastructure";
 82→  }
 83→  if (VALIDATION_ERROR_PATTERNS.test(errorType) || VALIDATION_ERROR_PATTERNS.test(message)) {
 84→    return "validation";
 85→  }
 86→  if (RUNTIME_ERROR_TYPES.has(errorType)) {
 87→    return "runtime";
 88→  }
 89→  return "unknown";
 90→}
 91→
 92→/** Cache of compiled modules to avoid re-transpiling on every execute call. */
 93→const compiledModuleCache = new Map<string, Record<string, unknown>>();
 94→
 95→/**
 96→ * Proxy console used in VM sandboxes. Delegates all calls to `consoleTarget`,
 97→ * which can be swapped at execution time to capture output as side effects.
 98→ */
 99→let consoleTarget: Console = console;
100→
101→const consoleProxy = new Proxy(console, {
102→  get(_target, prop, receiver) {
103→    const value = Reflect.get(consoleTarget, prop, receiver);
104→    if (typeof value === "function") {
105→      return value.bind(consoleTarget);
106→    }
107→    return value;
108→  },
109→});
110→
111→/**
112→ * Set the project root for module resolution. When set, NODE_PATH includes
113→ * the project's node_modules directory so createRequire() resolves packages.
114→ */
115→export function setProjectRoot(projectRoot: string | null | undefined): void {
116→  if (projectRoot) {
117→    const nodeModules = path.join(projectRoot, "node_modules");
118→    const existing = process.env["NODE_PATH"] ?? "";
119→    if (!existing.split(path.delimiter).includes(nodeModules)) {
120→      process.env["NODE_PATH"] = existing ? `${nodeModules}${path.delimiter}${existing}` : nodeModules;
121→      // Force Node to re-read NODE_PATH for future require calls
122→      require("module").Module._initPaths();
123→    }
124→  }
125→}
126→
127→/**
128→ * Wrap a require function to intercept React module imports for .tsx files.
129→ * Non-.tsx files get the original require unchanged.
130→ */
131→function wrapRequireWithReactShim(
132→  originalRequire: NodeRequire,
133→  filePath: string | undefined,
134→): NodeRequire {
135→  if (!filePath || !filePath.endsWith(".tsx")) return originalRequire;
136→
137→  const wrapped = ((modulePath: string) => {
138→    if (REACT_MODULE_NAMES.has(modulePath)) {
139→      return getReactShim(modulePath);
140→    }
141→    return originalRequire(modulePath);
142→  }) as NodeRequire;
143→
144→  // Preserve require.resolve and require.cache for compatibility
145→  wrapped.resolve = originalRequire.resolve;
146→  wrapped.cache = originalRequire.cache;
147→  wrapped.extensions = originalRequire.extensions;
148→  wrapped.main = originalRequire.main;
149→
150→  return wrapped;
151→}
152→
153→/**
154→ * Transpile a TypeScript file to JavaScript and return the exports object.
155→ *
156→ * Results are cached by absolute file path.
157→ */
158→function loadModule(filePath: string): Record<string, unknown> {
159→  const absolutePath = path.resolve(filePath);
160→  const cached = compiledModuleCache.get(absolutePath);
161→  if (cached) return cached;
162→
163→  const source = fs.readFileSync(absolutePath, "utf-8");
164→  const result = ts.transpileModule(source, {
165→    compilerOptions: {
166→      target: ts.ScriptTarget.ES2022,
167→      module: ts.ModuleKind.CommonJS,
168→      esModuleInterop: true,
169→      strict: true,
170→      jsx: ts.JsxEmit.ReactJSX,
171→    },
172→    fileName: absolutePath,
173→  });
174→
175→  const targetRequire = wrapRequireWithReactShim(createRequire(absolutePath), absolutePath);
176→  const moduleExports: Record<string, unknown> = {};
177→  const moduleObj = { exports: moduleExports };
178→
179→  const sandbox = vm.createContext({
180→    module: moduleObj,
181→    exports: moduleExports,
182→    require: targetRequire,
183→    console: consoleProxy,
184→    process,
185→    Buffer,
186→    setTimeout,
187→    clearTimeout,
188→    setInterval,
189→    clearInterval,
190→    __filename: absolutePath,
191→    __dirname: path.dirname(absolutePath),
192→  });
193→
194→  vm.runInContext(result.outputText, sandbox, { filename: absolutePath, timeout: getExecTimeoutMs() });
195→
196→  // After CommonJS execution, module.exports may have been reassigned
197→  const finalExports = (sandbox as Record<string, unknown>)["module"] as { exports: Record<string, unknown> };
198→  const resolvedExports = finalExports.exports;
199→
200→  compiledModuleCache.set(absolutePath, resolvedExports);
201→  return resolvedExports;
202→}
203→
204→/**
205→ * Look up a function from the file path and function name.
206→ *
207→ * The function name may be a simple name like "classifyNumber" which is
208→ * looked up directly on the module exports. If it contains a colon
209→ * (file:function format from the analyze phase), the file portion is
210→ * stripped and only the function name is used.
211→ */
212→function resolveFunction(
213→  filePath: string,
214→  functionRef: string,
215→): (...args: unknown[]) => unknown {
216→  // Strip file prefix if present (e.g. "examples/foo.ts:myFunc" → "myFunc")
217→  const funcName = functionRef.includes(":")
218→    ? functionRef.split(":").pop()!
219→    : functionRef;
220→
221→  const moduleExports = loadModule(filePath);
222→  const fn = moduleExports[funcName];
223→
224→  if (typeof fn !== "function") {
225→    throw new Error(
226→      `Function "${funcName}" not found in exports of ${filePath}. ` +
227→      `Available exports: ${Object.keys(moduleExports).join(", ")}`,
228→    );
229→  }
230→
231→  return fn as (...args: unknown[]) => unknown;
232→}
233→
234→/**
235→ * Run garbage collection if --expose-gc is enabled.
236→ * This gives more accurate heap measurements by clearing unreachable objects.
237→ */
238→function tryGc(): void {
239→  if (typeof globalThis.gc === "function") {
240→    globalThis.gc();
241→  }
242→}
243→
244→/** Result of measuring a function execution. */
245→interface MeasuredExecution {
246→  returnValue: unknown;
247→  thrownError: ErrorInfo | null;
248→  performance: PerformanceMetrics;
249→}
250→
251→/**
252→ * Execute a callback with full performance instrumentation.
253→ *
254→ * Measures wall time via process.hrtime.bigint(), CPU time via process.cpuUsage(),
255→ * and heap delta via process.memoryUsage(). Optionally runs GC before measurement
256→ * if --expose-gc is enabled.
257→ */
258→async function measureExecution(fn: () => unknown): Promise<MeasuredExecution> {
259→  tryGc();
260→
261→  const startMem = process.memoryUsage();
262→  const startCpu = process.cpuUsage();
263→  const startTime = process.hrtime.bigint();
264→
265→  let returnValue: unknown = null;
266→  let thrownError: ErrorInfo | null = null;
267→
268→  try {
269→    const syncResult = fn();
270→    // If the function returned a Promise (async function), await it with timeout
271→    if (syncResult != null && typeof (syncResult as PromiseLike<unknown>).then === 'function') {
272→      const timeoutMs = getExecTimeoutMs();
273→      returnValue = await Promise.race([
274→        syncResult as Promise<unknown>,
275→        new Promise<never>((_, reject) =>
276→          setTimeout(() => reject(new Error("async execution timed out")), timeoutMs)
277→        ),
278→      ]);
279→    } else {
280→      returnValue = syncResult;
281→    }
282→  } catch (e: unknown) {
283→    const err = e as { constructor?: { name?: string }; message?: string; stack?: string };
284→    const errorType = err.constructor?.name ?? "Error";
285→    const errorMessage = String(err.message ?? e);
286→    thrownError = {
287→      error_type: errorType,
288→      message: errorMessage,
289→      stack: err.stack ?? null,
290→      error_category: classifyError(errorType, errorMessage),
291→    };
292→  }
293→
294→  const endTime = process.hrtime.bigint();
295→  const endCpu = process.cpuUsage(startCpu);
296→  const endMem = process.memoryUsage();
297→
298→  const wallTimeNs = endTime - startTime;
299→  const wallTimeMs = Number(wallTimeNs) / 1_000_000;
300→  const cpuTimeUs = endCpu.user + endCpu.system;
301→
302→  return {
303→    returnValue,
304→    thrownError,
305→    performance: {
306→      wall_time_ms: wallTimeMs,
307→      cpu_time_us: cpuTimeUs,
308→      heap_used_bytes: Math.max(0, endMem.heapUsed - startMem.heapUsed),
309→      heap_allocated_bytes: Math.max(0, endMem.heapTotal - startMem.heapTotal),
310→    },
311→  };
312→}
