328→/**
329→ * Truncate a message string to fit within maxBytes.
330→ * If truncated, appends a suffix indicating the message was cut.
331→ */
332→export function truncateMessage(msg: string, maxBytes: number = MESSAGE_MAX_BYTES): string {
333→  const bytes = Buffer.byteLength(msg, "utf-8");
334→  if (bytes <= maxBytes) return msg;
335→  const suffix = "…[truncated]";
336→  const suffixBytes = Buffer.byteLength(suffix, "utf-8");
337→  const target = maxBytes - suffixBytes;
338→  let end = Math.min(msg.length, target);
339→  while (Buffer.byteLength(msg.slice(0, end), "utf-8") > target && end > 0) {
340→    end--;
341→  }
342→  return msg.slice(0, end) + suffix;
343→}
344→
345→/**
346→ * Truncate console_output side effects if they exceed head+tail line limits.
347→ * Returns the (possibly truncated) effects array and truncation metadata.
348→ */
349→export function truncateSideEffects(
350→  effects: SideEffect[],
351→  headLines: number = CAPTURE_HEAD_LINES,
352→  tailLines: number = CAPTURE_TAIL_LINES,
353→): { effects: SideEffect[]; truncation?: TruncationInfo } {
354→  const consoleIndices: number[] = [];
355→  for (let i = 0; i < effects.length; i++) {
356→    const effect = effects[i];
357→    if (effect !== undefined && effect.kind === "console_output") {
358→      consoleIndices.push(i);
359→    }
360→  }
361→
362→  const consoleCount = consoleIndices.length;
363→  if (consoleCount <= headLines + tailLines) {
364→    return { effects };
365→  }
366→
367→  let originalBytes = 0;
368→  for (const idx of consoleIndices) {
369→    const e = effects[idx];
370→    if (e !== undefined && e.kind === "console_output") {
371→      originalBytes += Buffer.byteLength(e.message, "utf-8");
372→    }
373→  }
374→
375→  const keepHead = new Set(consoleIndices.slice(0, headLines));
376→  const keepTail = new Set(consoleIndices.slice(-tailLines));
377→  const truncatedCount = consoleCount - headLines - tailLines;
378→
379→  let keptBytes = 0;
380→  for (const idx of [...keepHead, ...keepTail]) {
381→    const e = effects[idx];
382→    if (e !== undefined && e.kind === "console_output") {
383→      keptBytes += Buffer.byteLength(e.message, "utf-8");
384→    }
385→  }
386→  const truncatedBytes = originalBytes - keptBytes;
387→
388→  const result: SideEffect[] = [];
389→  let markerInserted = false;
390→  for (let i = 0; i < effects.length; i++) {
391→    const effect = effects[i];
392→    if (effect === undefined) continue;
393→    if (effect.kind !== "console_output") {
394→      result.push(effect);
395→    } else if (keepHead.has(i)) {
396→      result.push(effect);
397→    } else if (keepTail.has(i)) {
398→      result.push(effect);
399→    } else if (!markerInserted) {
400→      result.push({
401→        kind: "console_output",
402→        level: "info",
403→        message: `[…truncated ${truncatedCount} lines / ${truncatedBytes} bytes…]`,
404→      });
405→      markerInserted = true;
406→    }
407→  }
408→
409→  return {
410→    effects: result,
411→    truncation: {
412→      was_truncated: true,
413→      original_lines: consoleCount,
414→      original_bytes: originalBytes,
415→    },
416→  };
417→}
