419→/**
420→ * Create an intercepting console that records all output as side effects.
421→ *
422→ * Captures: log, warn, error, info, debug (level mapped 1:1),
423→ * dir/table/dirxml (→ "log"), trace (→ "debug"), count/countReset (→ "log"),
424→ * time/timeEnd/timeLog (→ "log"). Non-output methods (group, clear, assert,
425→ * profile, timeStamp) delegate to the real console.
426→ */
427→function createCapturingConsole(sideEffects: SideEffect[]): Console {
428→  const makeLogger = (level: string) => (...args: unknown[]): void => {
429→    const message = truncateMessage(args.map((a) =>
430→      typeof a === "string" ? a : JSON.stringify(a) ?? String(a)
431→    ).join(" "));
432→    sideEffects.push({ kind: "console_output", level, message });
433→  };
434→
435→  const logFn = makeLogger("log");
436→  const debugFn = makeLogger("debug");
437→
438→  // Counters for console.count / console.countReset
439→  const counters = new Map<string, number>();
440→
441→  // Timers for console.time / console.timeEnd / console.timeLog
442→  const timers = new Map<string, number>();
443→
444→  return {
445→    log: logFn,
446→    warn: makeLogger("warn"),
447→    error: makeLogger("error"),
448→    info: makeLogger("info"),
449→    debug: debugFn,
450→    dir: (...args: unknown[]) => logFn(...args),
451→    table: (...args: unknown[]) => logFn(...args),
452→    dirxml: (...args: unknown[]) => logFn(...args),
453→    trace: (...args: unknown[]) => {
454→      debugFn("Trace:", ...args);
455→    },
456→    count: (label = "default") => {
457→      const n = (counters.get(label) ?? 0) + 1;
458→      counters.set(label, n);
459→      logFn(`${label}: ${n}`);
460→    },
461→    countReset: (label = "default") => {
462→      counters.set(label, 0);
463→    },
464→    time: (label = "default") => {
465→      timers.set(label, performance.now());
466→    },
467→    timeEnd: (label = "default") => {
468→      const start = timers.get(label);
469→      if (start !== undefined) {
470→        logFn(`${label}: ${(performance.now() - start).toFixed(3)}ms`);
471→        timers.delete(label);
472→      }
473→    },
474→    timeLog: (label = "default", ...args: unknown[]) => {
475→      const start = timers.get(label);
476→      if (start !== undefined) {
477→        logFn(`${label}: ${(performance.now() - start).toFixed(3)}ms`, ...args);
478→      }
479→    },
480→    assert: console.assert,
481→    clear: console.clear,
482→    group: console.group,
483→    groupCollapsed: console.groupCollapsed,
484→    groupEnd: console.groupEnd,
485→    profile: console.profile,
486→    profileEnd: console.profileEnd,
487→    timeStamp: console.timeStamp,
488→    Console: console.Console,
489→  } as unknown as Console;
490→}
