492→/**
493→ * Create a process-like object that intercepts stdout/stderr writes
494→ * and records them as side effects.
495→ */
496→function createCapturingProcess(sideEffects: SideEffect[]): typeof process {
497→  const makeStreamWriter = (level: string) => {
498→    const originalStream = level === "stdout" ? process.stdout : process.stderr;
499→    return new Proxy(originalStream, {
500→      get(target, prop) {
501→        if (prop === "write") {
502→          return (chunk: string | Uint8Array, ...rest: unknown[]): boolean => {
503→            const text = typeof chunk === "string" ? chunk : new TextDecoder().decode(chunk);
504→            const trimmed = text.replace(/\n$/, "");
505→            if (trimmed.length > 0) {
506→              const message = truncateMessage(trimmed);
507→              sideEffects.push({ kind: "console_output", level, message });
508→            }
509→            return true;
510→          };
511→        }
512→        const val = Reflect.get(target, prop, target);
513→        return typeof val === "function" ? val.bind(target) : val;
514→      },
515→    });
516→  };
517→
518→  return new Proxy(process, {
519→    get(target, prop) {
520→      if (prop === "stdout") return makeStreamWriter("stdout");
521→      if (prop === "stderr") return makeStreamWriter("stderr");
522→      const val = Reflect.get(target, prop, target);
523→      return typeof val === "function" ? val.bind(target) : val;
524→    },
525→  });
526→}
