528→/**
529→ * Execute a function with the given inputs and capture the result.
530→ */
531→export async function executeFunction(
532→  filePath: string,
533→  functionRef: string,
534→  inputs: unknown[],
535→): Promise<RawExecuteResult> {
536→  const fn = resolveFunction(filePath, functionRef);
537→
538→  const sideEffects: SideEffect[] = [];
539→  const previousTarget = consoleTarget;
540→  consoleTarget = createCapturingConsole(sideEffects);
541→
542→  let metrics: MeasuredExecution;
543→  try {
544→    const reconstructedInputs = inputs.map(reconstructValue);
545→    metrics = await measureExecution(() => fn(...reconstructedInputs));
546→  } finally {
547→    consoleTarget = previousTarget;
548→  }
549→
550→  if (metrics.thrownError) {
551→    sideEffects.push({
552→      kind: "thrown_error",
553→      error_type: metrics.thrownError.error_type,
554→      message: metrics.thrownError.message,
555→      stack: metrics.thrownError.stack,
556→    });
557→  }
558→
559→  return {
560→    return_value: metrics.returnValue ?? null,
561→    thrown_error: metrics.thrownError,
562→    side_effects: sideEffects,
563→    branch_path: [],
564→    path_constraints: [],
565→    lines_executed: [],
566→    performance: metrics.performance,
567→    calls_to_external: [],
568→    scope_events: [],
569→    discovered_dependencies: [],
570→  };
571→}
