 55→func genParamInfo() *rapid.Generator[ParamInfo] {
 56→	return rapid.Custom[ParamInfo](func(t *rapid.T) ParamInfo {
 57→		return ParamInfo{
 58→			Name: genIdent().Draw(t, "name"),
 59→			Type: genTypeInfo(2).Draw(t, "type"),
 60→		}
 61→	})
 62→}
