420→// TestPropertyAnalyzeExtractsCorrectParams generates simple Go functions with
421→// known signatures and verifies AnalyzeFile extracts the right parameter count,
422→// names, and types.
423→func TestPropertyAnalyzeExtractsCorrectParams(t *testing.T) {
424→	rapid.Check(t, func(t *rapid.T) {
425→		goTypes := []string{"int", "int64", "float64", "string", "bool"}
426→
427→		nParams := rapid.IntRange(0, 4).Draw(t, "nParams")
428→		type paramSpec struct {
429→			name   string
430→			goType string
431→		}
432→		var params []paramSpec
433→		for i := 0; i < nParams; i++ {
434→			name := rapid.StringMatching(`[a-z][a-z0-9]{0,5}`).Draw(t, fmt.Sprintf("name%d", i))
435→			goType := rapid.SampledFrom(goTypes).Draw(t, fmt.Sprintf("type%d", i))
436→			params = append(params, paramSpec{name: name, goType: goType})
437→		}
438→
439→		// Build source
440→		var paramList []string
441→		for _, p := range params {
442→			paramList = append(paramList, fmt.Sprintf("%s %s", p.name, p.goType))
443→		}
444→		src := fmt.Sprintf("package p\n\nfunc Foo(%s) int { return 0 }\n", strings.Join(paramList, ", "))
445→
446→		// Write to temp file
447→		dir, err := os.MkdirTemp("", "shatter-go-prop-*")
448→		if err != nil {
449→			t.Fatalf("mkdirtemp: %v", err)
450→		}
451→		defer os.RemoveAll(dir)
452→		fpath := filepath.Join(dir, "test.go")
453→		if err := os.WriteFile(fpath, []byte(src), 0o644); err != nil {
454→			t.Fatalf("write temp file: %v", err)
455→		}
456→
457→		results, err := AnalyzeFile(fpath, "Foo")
458→		if err != nil {
459→			t.Fatalf("AnalyzeFile: %v", err)
460→		}
461→		if len(results) != 1 {
462→			t.Fatalf("expected 1 function, got %d", len(results))
463→		}
464→
465→		fa := results[0]
466→		if fa.Name != "Foo" {
467→			t.Fatalf("name: got %q, want %q", fa.Name, "Foo")
468→		}
469→		if len(fa.Params) != nParams {
470→			t.Fatalf("param count: got %d, want %d", len(fa.Params), nParams)
471→		}
472→		for i, p := range params {
473→			if fa.Params[i].Name != p.name {
474→				t.Fatalf("param[%d] name: got %q, want %q", i, fa.Params[i].Name, p.name)
475→			}
476→			expectedKind := goTypeMap[p.goType]
477→			if fa.Params[i].Type.Kind != expectedKind {
478→				t.Fatalf("param[%d] type: got %q, want %q (Go type %s)", i, fa.Params[i].Type.Kind, expectedKind, p.goType)
479→			}
480→		}
481→	})
482→}
