502→// ---------------------------------------------------------------------------
503→// Mock support
504→// ---------------------------------------------------------------------------
505→
506→/** Parsed mock lookup: maps "module:symbol" to the MockConfig. */
507→type MockLookup = Map<string, MockConfig>;
508→
509→/**
510→ * Build a lookup map from mock configs keyed by "module:symbol".
511→ * The module is extracted from the symbol field if it contains a colon,
512→ * otherwise the symbol is used as-is.
513→ */
514→function buildMockLookup(mocks: MockConfig[]): MockLookup {
515→  const lookup = new Map<string, MockConfig>();
516→  for (const mock of mocks) {
517→    lookup.set(mock.symbol, mock);
518→  }
519→  return lookup;
520→}
