693→          stmt.elseStatement.getStart(ctx.sourceFile),
694→        ).line + 1;
695→        ctx.instrumentableLines.add(elseIfLine);
696→        const nestedIf = instrumentStatement(stmt.elseStatement, ctx);
697→        instrumentedElse = ctx.factory.createBlock(
