2096→/// matching return values. Both children have the same number of configs
2097→/// with the same symbols as the parents.
2098→pub fn crossover_mock_values(
2099→    parent_a: &[MockConfig],
2100→    parent_b: &[MockConfig],
2101→    mock_params: &[MockParam],
2102→    crossover_rate: f64,
2103→    rng: &mut impl Rng,
2104→) -> (Vec<MockConfig>, Vec<MockConfig>) {
2105→    let len = parent_a.len().min(parent_b.len()).min(mock_params.len());
2106→
2107→    if rng.random_range(0.0..1.0_f64) >= crossover_rate {
2108→        return (parent_a.to_vec(), parent_b.to_vec());
2109→    }
2110→
2111→    let mut child1 = Vec::with_capacity(len);
2112→    let mut child2 = Vec::with_capacity(len);
2113→
2114→    for i in 0..len {
