303→// paramInfo holds a parameter's name and Go type string for harness generation.
304→type paramInfo struct {
305→	Name   string
306→	GoType string
307→}
308→
309→// returnTypeInfo describes what the function returns.
310→type returnTypeInfo struct {
311→	Count  int      // number of return values
312→	Types  []string // Go type strings
313→	HasErr bool     // last return is error
314→}
315→
316→// analyzeForExecution parses the source file and extracts parameter types
317→// and return type for the named function.
318→func analyzeForExecution(sourcePath, funcName string) ([]paramInfo, returnTypeInfo, error) {
319→	fset := token.NewFileSet()
320→	file, err := parser.ParseFile(fset, sourcePath, nil, parser.ParseComments)
321→	if err != nil {
322→		return nil, returnTypeInfo{}, fmt.Errorf("parsing %s: %w", sourcePath, err)
323→	}
324→
325→	// Type-check for better type resolution
326→	info := &types.Info{
327→		Types: make(map[ast.Expr]types.TypeAndValue),
328→		Defs:  make(map[*ast.Ident]types.Object),
329→		Uses:  make(map[*ast.Ident]types.Object),
330→	}
331→	conf := types.Config{
332→		Importer: importer.Default(),
333→		Error:    func(error) {},
334→	}
335→	conf.Check(file.Name.Name, fset, []*ast.File{file}, info) //nolint:errcheck
336→
337→	for _, decl := range file.Decls {
338→		fn, ok := decl.(*ast.FuncDecl)
339→		if !ok || fn.Name.Name != funcName {
340→			continue
341→		}
342→
343→		pkgName := file.Name.Name
344→		params := extractParamInfo(fn, info, pkgName)
345→		retInfo := extractReturnInfo(fn, info, pkgName)
346→		return params, retInfo, nil
347→	}
348→
349→	return nil, returnTypeInfo{}, fmt.Errorf("function not found: %s", funcName)
350→}
351→
352→func extractParamInfo(fn *ast.FuncDecl, info *types.Info, pkgName string) []paramInfo {
353→	if fn.Type.Params == nil {
354→		return nil
355→	}
356→	var params []paramInfo
357→	for _, field := range fn.Type.Params.List {
358→		goType := resolveGoType(field.Type, info, pkgName)
359→		for _, name := range field.Names {
360→			params = append(params, paramInfo{Name: name.Name, GoType: goType})
361→		}
362→	}
363→	return params
364→}
365→
366→func extractReturnInfo(fn *ast.FuncDecl, info *types.Info, pkgName string) returnTypeInfo {
367→	results := fn.Type.Results
368→	if results == nil || len(results.List) == 0 {
369→		return returnTypeInfo{}
370→	}
371→
372→	var retTypes []string
373→	for _, field := range results.List {
374→		goType := resolveGoType(field.Type, info, pkgName)
375→		if len(field.Names) == 0 {
376→			retTypes = append(retTypes, goType)
377→		} else {
378→			for range field.Names {
379→				retTypes = append(retTypes, goType)
380→			}
381→		}
382→	}
383→
384→	hasErr := len(retTypes) > 0 && retTypes[len(retTypes)-1] == "error"
385→	return returnTypeInfo{
386→		Count:  len(retTypes),
387→		Types:  retTypes,
388→		HasErr: hasErr,
389→	}
390→}
391→
392→// resolveGoType returns the Go type string for a type expression.
393→// The pkgName parameter is the source file's package name; types qualified
394→// with this prefix (e.g. "examples.User") are stripped to the bare name
395→// because the instrumented code is rewritten to package main.
396→func resolveGoType(expr ast.Expr, info *types.Info, pkgName string) string {
397→	if tv, ok := info.Types[expr]; ok {
398→		s := tv.Type.String()
399→		return stripLocalPkg(s, pkgName)
400→	}
401→	// Fallback to AST-based type string
402→	return astTypeString(expr)
403→}
404→
405→// stripLocalPkg removes occurrences of "pkgName." from a type string so that
406→// types defined in the same package work after rewriting to package main.
407→func stripLocalPkg(typeStr, pkgName string) string {
408→	if pkgName == "" {
409→		return typeStr
410→	}
411→	return strings.ReplaceAll(typeStr, pkgName+".", "")
412→}
413→
414→func astTypeString(expr ast.Expr) string {
415→	switch e := expr.(type) {
416→	case *ast.Ident:
417→		return e.Name
418→	case *ast.ArrayType:
419→		if e.Len == nil {
420→			return "[]" + astTypeString(e.Elt)
421→		}
422→		return "[" + astTypeString(e.Len) + "]" + astTypeString(e.Elt)
423→	case *ast.StarExpr:
424→		return "*" + astTypeString(e.X)
425→	case *ast.MapType:
426→		return "map[" + astTypeString(e.Key) + "]" + astTypeString(e.Value)
427→	case *ast.SelectorExpr:
428→		return astTypeString(e.X) + "." + e.Sel.Name
429→	case *ast.InterfaceType:
430→		return "interface{}"
431→	case *ast.BasicLit:
432→		return e.Value
433→	default:
434→		return "interface{}"
435→	}
436→}
437→
438→// generateHarness creates a main.go that deserializes inputs, calls the function,
439→// captures results, and writes output files.
440→func generateHarness(funcName string, params []paramInfo, retInfo returnTypeInfo, inputs []json.RawMessage, resultsPath, returnPath, perfPath string, hasMocks bool) (string, error) {
441→	var b strings.Builder
442→
443→	b.WriteString("package main\n\n")
444→	b.WriteString("import (\n")
445→	b.WriteString("\t\"encoding/json\"\n")
446→	b.WriteString("\t\"fmt\"\n")
447→	b.WriteString("\t\"os\"\n")
448→	b.WriteString("\t\"runtime\"\n")
449→	b.WriteString("\t\"time\"\n")
450→	b.WriteString(")\n\n")
451→
452→	b.WriteString("func main() {\n")
453→
454→	// If mocks are active, defer dumping external call records
455→	if hasMocks {
456→		b.WriteString("\tdefer shatterDumpMockCalls()\n\n")
457→	}
458→	b.WriteString("\tvar memBefore runtime.MemStats\n")
459→	b.WriteString("\truntime.ReadMemStats(&memBefore)\n")
460→	b.WriteString("\tcpuStart := time.Now()\n\n")
461→
462→	// Declare and deserialize each input parameter
463→	for i, p := range params {
464→		inputJSON, err := json.Marshal(string(inputs[i]))
465→		if err != nil {
466→			return "", fmt.Errorf("marshaling input %d: %w", i, err)
467→		}
468→
469→		// Write the raw JSON as a string literal, then unmarshal into the typed var
470→		b.WriteString(fmt.Sprintf("\tvar %s %s\n", p.Name, p.GoType))
471→		b.WriteString(fmt.Sprintf("\tif err := json.Unmarshal([]byte(%s), &%s); err != nil {\n", inputJSON, p.Name))
472→		b.WriteString(fmt.Sprintf("\t\tfmt.Fprintf(os.Stderr, \"failed to unmarshal input %s: %%v\\n\", err)\n", p.Name))
473→		b.WriteString("\t\tos.Exit(1)\n")
474→		b.WriteString("\t}\n")
475→	}
476→
477→	b.WriteString("\n")
478→
479→	// Call the function
480→	argList := make([]string, len(params))
481→	for i, p := range params {
482→		argList[i] = p.Name
483→	}
484→	callExpr := fmt.Sprintf("%s(%s)", funcName, strings.Join(argList, ", "))
485→
486→	if retInfo.Count == 0 {
487→		b.WriteString(fmt.Sprintf("\t%s\n", callExpr))
488→	} else if retInfo.Count == 1 {
489→		b.WriteString(fmt.Sprintf("\tresult := %s\n", callExpr))
490→	} else {
491→		// Multiple returns: capture into named vars
492→		retVars := make([]string, retInfo.Count)
493→		for i := range retInfo.Count {
494→			if i == retInfo.Count-1 && retInfo.HasErr {
495→				retVars[i] = "retErr"
496→			} else {
497→				retVars[i] = fmt.Sprintf("ret%d", i)
498→			}
499→		}
500→		b.WriteString(fmt.Sprintf("\t%s := %s\n", strings.Join(retVars, ", "), callExpr))
501→
502→		// If last return is error, check it
503→		if retInfo.HasErr {
504→			b.WriteString("\tif retErr != nil {\n")
505→			b.WriteString("\t\tfmt.Fprintf(os.Stderr, \"function returned error: %v\\n\", retErr)\n")
506→			b.WriteString("\t}\n")
507→		}
508→
509→		// Build a result struct for serialization
510→		if retInfo.Count == 1 || (retInfo.Count == 2 && retInfo.HasErr) {
511→			// Single meaningful return (possibly with error)
512→			b.WriteString(fmt.Sprintf("\tresult := ret0\n"))
513→		} else {
514→			// Multiple returns: wrap in a slice
515→			nonErrVars := retVars
516→			if retInfo.HasErr {
517→				nonErrVars = retVars[:len(retVars)-1]
518→			}
519→			ifaceVars := make([]string, len(nonErrVars))
520→			for i, v := range nonErrVars {
521→				ifaceVars[i] = fmt.Sprintf("any(%s)", v)
522→			}
523→			b.WriteString(fmt.Sprintf("\tresult := []any{%s}\n", strings.Join(ifaceVars, ", ")))
524→		}
525→	}
526→
527→	b.WriteString("\n")
528→
529→	// Dump shatter recording results
530→	resultsPathEscaped := strings.ReplaceAll(resultsPath, `\`, `\\`)
531→	b.WriteString(fmt.Sprintf("\tif err := __shatter_dump_results(%q); err != nil {\n", resultsPathEscaped))
532→	b.WriteString("\t\tfmt.Fprintf(os.Stderr, \"failed to dump results: %v\\n\", err)\n")
533→	b.WriteString("\t}\n")
534→
535→	// Write return value as JSON
536→	if retInfo.Count > 0 {
537→		returnPathEscaped := strings.ReplaceAll(returnPath, `\`, `\\`)
538→		b.WriteString(fmt.Sprintf("\n\treturnData, err := json.Marshal(result)\n"))
539→		b.WriteString("\tif err != nil {\n")
540→		b.WriteString("\t\tfmt.Fprintf(os.Stderr, \"failed to marshal return: %v\\n\", err)\n")
541→		b.WriteString("\t} else {\n")
542→		b.WriteString(fmt.Sprintf("\t\tos.WriteFile(%q, returnData, 0644)\n", returnPathEscaped))
543→		b.WriteString("\t}\n")
544→	}
545→
546→	// Write performance metrics
547→	perfPathEscaped := strings.ReplaceAll(perfPath, `\`, `\\`)
548→	b.WriteString("\n\tcpuElapsed := time.Since(cpuStart)\n")
549→	b.WriteString("\tvar memAfter runtime.MemStats\n")
550→	b.WriteString("\truntime.ReadMemStats(&memAfter)\n")
551→	b.WriteString("\tperfData, _ := json.Marshal(map[string]any{\n")
552→	b.WriteString("\t\t\"cpu_time_us\": cpuElapsed.Microseconds(),\n")
553→	b.WriteString("\t\t\"heap_used_bytes\": memAfter.HeapInuse - memBefore.HeapInuse,\n")
554→	b.WriteString("\t\t\"heap_allocated_bytes\": memAfter.TotalAlloc - memBefore.TotalAlloc,\n")
555→	b.WriteString("\t})\n")
556→	b.WriteString(fmt.Sprintf("\tos.WriteFile(%q, perfData, 0644)\n", perfPathEscaped))
557→
558→	b.WriteString("}\n")
559→
560→	return b.String(), nil
561→}
562→
563→// generateMockFile creates a Go source file providing a mock registry and call
564→// tracking. Each mock symbol gets a package-level function variable that returns
565→// pre-configured values and records calls to a JSON file.
566→func generateMockFile(mocks []MockConfig, externalCallsPath string) string {
567→	var b strings.Builder
568→
569→	b.WriteString("package main\n\n")
570→	b.WriteString("import (\n")
571→	b.WriteString("\t\"encoding/json\"\n")
572→	b.WriteString("\t\"os\"\n")
573→	b.WriteString("\t\"sync\"\n")
574→	b.WriteString(")\n\n")
575→
576→	// Mock call record type
577→	b.WriteString("type shatterMockCall struct {\n")
578→	b.WriteString("\tSymbol      string          `json:\"symbol\"`\n")
579→	b.WriteString("\tArgs        json.RawMessage `json:\"args\"`\n")
580→	b.WriteString("\tReturnValue json.RawMessage `json:\"return_value\"`\n")
581→	b.WriteString("}\n\n")
582→
583→	// Global call recorder
584→	b.WriteString("var (\n")
585→	b.WriteString("\tshatterMockCalls   []shatterMockCall\n")
586→	b.WriteString("\tshatterMockCallsMu sync.Mutex\n")
587→	b.WriteString(")\n\n")
588→
589→	// Record helper
590→	b.WriteString("func shatterRecordMockCall(symbol string, args any, retVal any) {\n")
591→	b.WriteString("\targsJSON, _ := json.Marshal(args)\n")
592→	b.WriteString("\tretJSON, _ := json.Marshal(retVal)\n")
593→	b.WriteString("\tshatterMockCallsMu.Lock()\n")
594→	b.WriteString("\tshatterMockCalls = append(shatterMockCalls, shatterMockCall{\n")
595→	b.WriteString("\t\tSymbol:      symbol,\n")
596→	b.WriteString("\t\tArgs:        argsJSON,\n")
597→	b.WriteString("\t\tReturnValue: retJSON,\n")
598→	b.WriteString("\t})\n")
599→	b.WriteString("\tshatterMockCallsMu.Unlock()\n")
600→	b.WriteString("}\n\n")
601→
602→	// Dump function
603→	pathEscaped := strings.ReplaceAll(externalCallsPath, `\`, `\\`)
604→	b.WriteString("func shatterDumpMockCalls() {\n")
605→	b.WriteString("\tshatterMockCallsMu.Lock()\n")
606→	b.WriteString("\tdefer shatterMockCallsMu.Unlock()\n")
607→	b.WriteString("\tdata, _ := json.Marshal(shatterMockCalls)\n")
608→	b.WriteString(fmt.Sprintf("\tos.WriteFile(%q, data, 0644)\n", pathEscaped))
609→	b.WriteString("}\n\n")
610→
611→	// Generate a mock function variable for each symbol.
612→	// The mock returns the pre-configured return values in order,
613→	// repeating the last one when exhausted (repeat_last behavior).
614→	for i, mock := range mocks {
615→		if mock.DefaultBehavior == "passthrough" {
616→			continue
617→		}
618→
619→		// Sanitize symbol to valid Go identifier
620→		safeName := sanitizeMockName(mock.Symbol)
621→
622→		// Serialize return values as JSON array
623→		retValsJSON, _ := json.Marshal(mock.ReturnValues)
624→
625→		b.WriteString(fmt.Sprintf("// Mock for %s\n", mock.Symbol))
626→		b.WriteString(fmt.Sprintf("var shatterMock%d_retvals = func() []json.RawMessage {\n", i))
627→		b.WriteString(fmt.Sprintf("\tvar vals []any\n"))
628→		b.WriteString(fmt.Sprintf("\tjson.Unmarshal([]byte(`%s`), &vals)\n", string(retValsJSON)))
629→		b.WriteString("\tresult := make([]json.RawMessage, len(vals))\n")
630→		b.WriteString("\tfor i, v := range vals {\n")
631→		b.WriteString("\t\tresult[i], _ = json.Marshal(v)\n")
632→		b.WriteString("\t}\n")
633→		b.WriteString("\treturn result\n")
634→		b.WriteString("}()\n")
635→		b.WriteString(fmt.Sprintf("var shatterMock%d_callIdx int\n\n", i))
636→
637→		// Generate the mock function
638→		b.WriteString(fmt.Sprintf("// ShatterMock_%s returns pre-configured values for %s.\n", safeName, mock.Symbol))
639→		b.WriteString(fmt.Sprintf("func ShatterMock_%s(args ...any) any {\n", safeName))
640→		b.WriteString(fmt.Sprintf("\tretvals := shatterMock%d_retvals\n", i))
641→		b.WriteString(fmt.Sprintf("\tidx := shatterMock%d_callIdx\n", i))
642→
643→		if mock.DefaultBehavior == "repeat_last" || mock.DefaultBehavior == "" {
644→			b.WriteString("\tif idx >= len(retvals) && len(retvals) > 0 {\n")
645→			b.WriteString("\t\tidx = len(retvals) - 1\n")
646→			b.WriteString("\t}\n")
647→		} else {
648→			b.WriteString("\tif len(retvals) > 0 {\n")
649→			b.WriteString("\t\tidx = idx % len(retvals)\n")
650→			b.WriteString("\t}\n")
651→		}
652→
653→		b.WriteString(fmt.Sprintf("\tshatterMock%d_callIdx++\n", i))
654→		b.WriteString("\n")
655→		b.WriteString("\tvar retVal any\n")
656→		b.WriteString("\tif idx < len(retvals) {\n")
657→		b.WriteString("\t\tjson.Unmarshal(retvals[idx], &retVal)\n")
658→		b.WriteString("\t}\n")
659→
660→		if mock.ShouldTrackCalls {
661→			b.WriteString(fmt.Sprintf("\tshatterRecordMockCall(%q, args, retVal)\n", mock.Symbol))
662→		}
663→
664→		b.WriteString("\treturn retVal\n")
665→		b.WriteString("}\n\n")
666→	}
667→
668→	// Use safeName to avoid "declared but not used" (it's used in the function name)
669→	b.WriteString("// Ensure shatter mock infrastructure is referenced.\n")
670→	b.WriteString("var _ = shatterDumpMockCalls\n")
671→
672→	return b.String()
673→}
674→
675→// sanitizeMockName converts a symbol name (e.g. "fs.readFile") to a valid Go identifier.
676→func sanitizeMockName(symbol string) string {
677→	result := make([]byte, 0, len(symbol))
678→	for _, c := range symbol {
679→		if (c >= 'a' && c <= 'z') || (c >= 'A' && c <= 'Z') || (c >= '0' && c <= '9') || c == '_' {
680→			result = append(result, byte(c))
681→		} else {
682→			result = append(result, '_')
683→		}
684→	}
685→	return string(result)
686→}
687→
688→// rewritePackageToMain rewrites the package declaration in all Go files in dir
689→// to "package main", so the harness main.go can call functions from those files.
690→func rewritePackageToMain(dir string) error {
691→	entries, err := os.ReadDir(dir)
692→	if err != nil {
693→		return err
694→	}
695→	for _, entry := range entries {
696→		if entry.IsDir() || filepath.Ext(entry.Name()) != ".go" || entry.Name() == "main.go" {
697→			continue
698→		}
699→		path := filepath.Join(dir, entry.Name())
700→		fset := token.NewFileSet()
701→		f, err := parser.ParseFile(fset, path, nil, parser.ParseComments)
702→		if err != nil {
703→			continue // skip unparseable files
704→		}
705→		if f.Name.Name == "main" {
706→			continue
707→		}
708→		f.Name.Name = "main"
709→		out, err := os.Create(path)
710→		if err != nil {
711→			return err
712→		}
713→		err = printer.Fprint(out, fset, f)
714→		out.Close()
715→		if err != nil {
716→			return err
717→		}
718→	}
719→	return nil
720→}
