313→func convertErrorInfo(e *instrument.ErrorInfo) *ErrorInfo {
314→	if e == nil {
315→		return nil
316→	}
317→	var stack *string
318→	if e.Stack != "" {
319→		stack = &e.Stack
320→	}
321→	return &ErrorInfo{
322→		ErrorType: e.ErrorType,
323→		Message:   e.Message,
324→		Stack:     stack,
325→	}
326→}
