 33→export const DEFAULT_EXEC_TIMEOUT_MS = 15_000;
 34→
 35→/** Default number of head console lines to keep before truncation. */
 36→export const CAPTURE_HEAD_LINES = 50;
 37→/** Default number of tail console lines to keep after truncation. */
 38→export const CAPTURE_TAIL_LINES = 20;
 39→/** Maximum total bytes for captured console output before truncation. */
 40→export const CAPTURE_MAX_BYTES = 6144;
 41→/** Maximum bytes for a single side-effect message. */
 42→export const MESSAGE_MAX_BYTES = 4096;
