 44→/**
 45→ * Read SHATTER_EXEC_TIMEOUT env var (seconds) and return milliseconds.
 46→ * Default: 15s. Ignores non-positive or non-numeric values.
 47→ */
 48→export function getExecTimeoutMs(): number {
 49→  const raw = process.env["SHATTER_EXEC_TIMEOUT"];
 50→  if (raw !== undefined) {
 51→    const secs = parseFloat(raw);
 52→    if (Number.isFinite(secs) && secs > 0) {
 53→      return secs * 1000;
 54→    }
 55→  }
 56→  return DEFAULT_EXEC_TIMEOUT_MS;
 57→}
