 92→/** Cache of compiled modules to avoid re-transpiling on every execute call. */
 93→const compiledModuleCache = new Map<string, Record<string, unknown>>();
 94→
 95→/**
 96→ * Proxy console used in VM sandboxes. Delegates all calls to `consoleTarget`,
 97→ * which can be swapped at execution time to capture output as side effects.
 98→ */
 99→let consoleTarget: Console = console;
100→
101→const consoleProxy = new Proxy(console, {
102→  get(_target, prop, receiver) {
103→    const value = Reflect.get(consoleTarget, prop, receiver);
104→    if (typeof value === "function") {
105→      return value.bind(consoleTarget);
106→    }
107→    return value;
108→  },
109→});
