204→/**
205→ * Look up a function from the file path and function name.
206→ *
207→ * The function name may be a simple name like "classifyNumber" which is
208→ * looked up directly on the module exports. If it contains a colon
209→ * (file:function format from the analyze phase), the file portion is
210→ * stripped and only the function name is used.
211→ */
212→function resolveFunction(
213→  filePath: string,
214→  functionRef: string,
215→): (...args: unknown[]) => unknown {
216→  // Strip file prefix if present (e.g. "examples/foo.ts:myFunc" → "myFunc")
217→  const funcName = functionRef.includes(":")
218→    ? functionRef.split(":").pop()!
219→    : functionRef;
220→
221→  const moduleExports = loadModule(filePath);
222→  const fn = moduleExports[funcName];
223→
224→  if (typeof fn !== "function") {
225→    throw new Error(
226→      `Function "${funcName}" not found in exports of ${filePath}. ` +
227→      `Available exports: ${Object.keys(moduleExports).join(", ")}`,
228→    );
229→  }
230→
231→  return fn as (...args: unknown[]) => unknown;
232→}
