314→/** Execution result before being wrapped in a protocol response. */
315→interface RawExecuteResult {
316→  return_value: unknown;
317→  thrown_error: ErrorInfo | null;
318→  performance: PerformanceMetrics;
319→  branch_path: BranchDecision[];
320→  path_constraints: SymConstraint[];
321→  lines_executed: number[];
322→  side_effects: SideEffect[];
323→  calls_to_external: ExternalCall[];
324→  scope_events: TraceEvent[];
