828→/**
829→ * Build a full ExecuteResponse from a raw execution result.
830→ * Applies side-effect truncation before assembling the response.
831→ */
832→export function buildExecuteResponse(
833→  id: number,
834→  protocolVersion: string,
835→  rawResult: RawExecuteResult,
836→): ExecuteResponse {
837→  const { effects, truncation } = truncateSideEffects(rawResult.side_effects);
838→
839→  const response: ExecuteResponse = {
840→    protocol_version: protocolVersion,
841→    id,
842→    status: "execute",
843→    return_value: rawResult.return_value,
844→    thrown_error: rawResult.thrown_error,
845→    branch_path: rawResult.branch_path,
846→    lines_executed: rawResult.lines_executed,
847→    calls_to_external: rawResult.calls_to_external,
848→    path_constraints: rawResult.path_constraints,
849→    side_effects: effects,
850→    performance: rawResult.performance,
851→    scope_events: rawResult.scope_events,
852→  };
853→
854→  if (truncation) {
855→    response.capture_truncation = truncation;
856→  }
857→
858→  if (rawResult.discovered_dependencies.length > 0) {
859→    response.discovered_dependencies = rawResult.discovered_dependencies;
860→  }
861→
862→  return response;
863→}
