 364→// ---------------------------------------------------------------------------
 365→// Convention-based setup file discovery
 366→// ---------------------------------------------------------------------------
 367→
 368→/// Filename for session-level setup in the project root: `shatter.setup.{ext}`.
 369→const SESSION_SETUP_ROOT_PREFIX: &str = "shatter.setup";
 370→
 371→/// Filename for session-level setup inside `.shatter/`: `setup.{ext}`.
 372→const SESSION_SETUP_DIR_NAME: &str = "setup";
 373→
 374→/// Infix marker for file-level setup files co-located with source:
 375→/// `<stem>.shatter.setup.{ext}`.
 376→const FILE_SETUP_INFIX: &str = ".shatter.setup.";
 377→
 378→/// The `.shatter` directory name.
 379→const SHATTER_DIR: &str = ".shatter";
 380→
 381→/// Discovered setup files organized by lifecycle level.
 382→#[derive(Debug, Clone, Default, PartialEq, Eq)]
 383→pub struct DiscoveredSetupFiles {
 384→    /// Session-level setup file (at most one).
 385→    pub session: Option<PathBuf>,
 386→    /// File-level setup entries: source file path → co-located setup file path.
 387→    pub file_level: HashMap<PathBuf, PathBuf>,
 388→}
 389→
 390→/// Config overrides that suppress convention-based discovery at specific levels.
 391→#[derive(Debug, Clone, Default)]
 392→pub struct SetupConfigOverride {
 393→    /// If `Some`, use this path instead of convention-discovered session setup.
 394→    /// Convention discovery for session level is skipped entirely.
 395→    pub session_file: Option<PathBuf>,
 396→    /// If `Some`, use these mappings instead of convention-discovered file-level setup.
 397→    /// Keys are source file paths, values are setup file paths.
 398→    pub file_level: Option<HashMap<PathBuf, PathBuf>>,
 399→}
 400→
 401→/// Discover setup files by convention, with optional config overrides.
 402→///
 403→/// Convention rules:
 404→/// - **Session**: `{root}/shatter.setup.{ext}` (root-level takes precedence)
 405→///   or `{root}/.shatter/setup.{ext}`.
 406→/// - **File-level**: `{dir}/{stem}.shatter.setup.{ext}` co-located with each
 407→///   source file in `source_files`.
 408→///
 409→/// When `config_override` specifies a value for a level, convention discovery
 410→/// for that level is skipped and the override is used directly.
 411→pub fn discover_setup_files(
 412→    project_root: &Path,
 413→    language_ext: &str,
 414→    source_files: &[PathBuf],
 415→    config_override: &SetupConfigOverride,
 416→) -> DiscoveredSetupFiles {
 417→    let session = if let Some(ref override_path) = config_override.session_file {
 418→        Some(override_path.clone())
 419→    } else {
 420→        discover_session_setup(project_root, language_ext)
 421→    };
 422→
 423→    let file_level = if let Some(ref override_map) = config_override.file_level {
 424→        override_map.clone()
 425→    } else {
 426→        discover_file_setup(language_ext, source_files)
 427→    };
 428→
 429→    DiscoveredSetupFiles {
 430→        session,
 431→        file_level,
 432→    }
 433→}
 434→
 435→/// Look for a session-level setup file by convention.
 436→/// Root-level `shatter.setup.{ext}` takes precedence over `.shatter/setup.{ext}`.
 437→fn discover_session_setup(project_root: &Path, language_ext: &str) -> Option<PathBuf> {
 438→    let root_candidate = project_root.join(format!("{SESSION_SETUP_ROOT_PREFIX}.{language_ext}"));
 439→    if root_candidate.is_file() {
 440→        return Some(root_candidate);
 441→    }
 442→
 443→    let dir_candidate = project_root
 444→        .join(SHATTER_DIR)
 445→        .join(format!("{SESSION_SETUP_DIR_NAME}.{language_ext}"));
 446→    if dir_candidate.is_file() {
 447→        return Some(dir_candidate);
 448→    }
 449→
 450→    None
 451→}
 452→
 453→/// Find file-level setup files co-located with source files.
 454→fn discover_file_setup(
 455→    language_ext: &str,
 456→    source_files: &[PathBuf],
 457→) -> HashMap<PathBuf, PathBuf> {
 458→    let mut result = HashMap::new();
 459→    for source in source_files {
 460→        let Some(stem) = source.file_stem().and_then(|s| s.to_str()) else {
 461→            continue;
 462→        };
 463→        let Some(parent) = source.parent() else {
 464→            continue;
 465→        };
 466→        let setup_name = format!("{stem}{FILE_SETUP_INFIX}{language_ext}");
 467→        let setup_path = parent.join(&setup_name);
 468→        if setup_path.is_file() {
 469→            result.insert(source.clone(), setup_path);
 470→        }
 471→    }
 472→    result
 473→}
