1284→/// Format a [`TypeInfo`] as a concise human-readable string.
1285→fn format_type(ty: &TypeInfo) -> String {
1286→    match ty {
1287→        TypeInfo::Int => "int".to_string(),
1288→        TypeInfo::Float => "float".to_string(),
1289→        TypeInfo::Str => "string".to_string(),
1290→        TypeInfo::Bool => "bool".to_string(),
1291→        TypeInfo::Array { element } => format!("{}[]", format_type(element)),
1292→        TypeInfo::Nullable { inner } => format!("{}?", format_type(inner)),
1293→        TypeInfo::Object { fields } => {
1294→            if fields.is_empty() {
1295→                "object".to_string()
1296→            } else {
1297→                let field_strs: Vec<String> = fields
1298→                    .iter()
1299→                    .map(|(name, t)| format!("{name}: {}", format_type(t)))
1300→                    .collect();
1301→                format!("{{{}}}", field_strs.join(", "))
1302→            }
1303→        }
1304→        TypeInfo::Union { variants } => {
1305→            variants
1306→                .iter()
1307→                .map(format_type)
1308→                .collect::<Vec<_>>()
1309→                .join(" | ")
1310→        }
1311→        TypeInfo::Complex { kind, .. } => format!("{kind:?}"),
1312→        TypeInfo::Opaque { label } => label.clone(),
1313→        TypeInfo::Unknown => "unknown".to_string(),
1314→    }
1315→}
