// Package protocol defines the Shatter frontend protocol types.
//
// These types match the JSON schemas in protocol/schemas/ and the Rust
// types in shatter-core/src/. The protocol uses newline-delimited JSON
// (NDJSON) over stdin/stdout between the core engine and language frontends.
package protocol

import (
	"encoding/json"
	"fmt"
)

const ProtocolVersion = "0.1.0"

// SetupLevel defines the lifecycle granularity for setup/teardown.
// Values match the Rust core's SetupLevel enum (snake_case serialization).
type SetupLevel string

const (
	SetupLevelSession   SetupLevel = "session"
	SetupLevelFile      SetupLevel = "file"
	SetupLevelFunction  SetupLevel = "function"
	SetupLevelExecution SetupLevel = "execution"
)

// ValidSetupLevels lists all valid setup levels for validation.
var ValidSetupLevels = []SetupLevel{
	SetupLevelSession, SetupLevelFile, SetupLevelFunction, SetupLevelExecution,
}

// IsValid returns true if the level is a recognized setup level.
func (l SetupLevel) IsValid() bool {
	for _, v := range ValidSetupLevels {
		if l == v {
			return true
		}
	}
	return false
}

// SetupContextEntry associates a lifecycle level with the opaque context
// value returned by its Setup command.
type SetupContextEntry struct {
	Level   SetupLevel       `json:"level"`
	Context *json.RawMessage `json:"context"`
}

// SetupContextStack is a stack of active setup contexts, ordered from
// outermost (session) to innermost (execution). Passed to Execute so
// frontends can restore all active setup state.
type SetupContextStack struct {
	Contexts []SetupContextEntry `json:"contexts"`
}

// Request is a message from the core engine to the frontend.
type Request struct {
	ProtocolVersion string `json:"protocol_version"`
	ID              int    `json:"id"`
	Command         string `json:"command"`

	// Handshake fields
	Capabilities []string `json:"capabilities,omitempty"`

	// Analyze fields
	File        string  `json:"file,omitempty"`
	Function    *string `json:"function,omitempty"`
	ProjectRoot *string `json:"project_root,omitempty"`

	// Instrument/Execute fields
	Mocks []MockConfig `json:"mocks,omitempty"`

	// Execute fields
	Inputs       []json.RawMessage  `json:"inputs,omitempty"`
	SetupContext *SetupContextStack `json:"setup_context,omitempty"`

	// Setup/Teardown fields
	Scope         string             `json:"scope,omitempty"`
	Level         SetupLevel         `json:"level,omitempty"`
	ParentContext *SetupContextStack `json:"parent_context,omitempty"`

	// Generate fields
	Name   string           `json:"name,omitempty"`
	Kind   string           `json:"kind,omitempty"`
	Recipe *json.RawMessage `json:"recipe,omitempty"`
}

// Response is a message from the frontend to the core engine.
// Only fields relevant to the given status are populated.
type Response struct {
	ProtocolVersion string `json:"protocol_version"`
	ID              int    `json:"id"`
	Status          string `json:"status"`

	// Handshake
	FrontendVersion string   `json:"frontend_version,omitempty"`
	Language        string   `json:"language,omitempty"`
	Capabilities    []string `json:"capabilities,omitempty"`

	// Analyze
	Functions []FunctionAnalysis `json:"functions"`

	// Instrument
	Instrumented           *bool   `json:"instrumented,omitempty"`
	OutputFile             *string `json:"output_file,omitempty"`
	InstrumentableLineCount *int   `json:"instrumentable_line_count,omitempty"`

	// Execute
	ReturnValue       json.RawMessage   `json:"return_value,omitempty"`
	ThrownError       *ErrorInfo        `json:"thrown_error,omitempty"`
	BranchPath        []BranchDecision  `json:"branch_path,omitempty"`
	LinesExecuted     []int             `json:"lines_executed,omitempty"`
	CallsToExternal        []ExternalCall         `json:"calls_to_external,omitempty"`
	DiscoveredDependencies []DiscoveredDependency `json:"discovered_dependencies,omitempty"`
	PathConstraints        []SymConstraint        `json:"path_constraints,omitempty"`
	SideEffects       []SideEffect      `json:"side_effects,omitempty"`
	ScopeEvents       []json.RawMessage `json:"scope_events,omitempty"`
	CaptureTruncation *TruncationInfo   `json:"capture_truncation,omitempty"`
	Performance       *PerfMetrics      `json:"performance,omitempty"`

	// Setup
	SetupContext *json.RawMessage `json:"setup_context,omitempty"`

	// Generate
	Value       *json.RawMessage `json:"value,omitempty"`
	GeneratorID string           `json:"generator_id,omitempty"`
	Recipe      *json.RawMessage `json:"recipe,omitempty"`

	// Error
	Code    string           `json:"code,omitempty"`
	Message string           `json:"message,omitempty"`
	Details *json.RawMessage `json:"details,omitempty"`
}

// ObjectField is a name-type pair for object fields.
// It serializes as a JSON 2-element array: ["fieldName", {type}].
type ObjectField struct {
	Name string
	Type TypeInfo
}

func (f ObjectField) MarshalJSON() ([]byte, error) {
	return json.Marshal([2]any{f.Name, f.Type})
}

func (f *ObjectField) UnmarshalJSON(data []byte) error {
	var raw [2]json.RawMessage
	if err := json.Unmarshal(data, &raw); err != nil {
		return fmt.Errorf("object field must be a 2-element array: %w", err)
	}
	if err := json.Unmarshal(raw[0], &f.Name); err != nil {
		return fmt.Errorf("object field name: %w", err)
	}
	if err := json.Unmarshal(raw[1], &f.Type); err != nil {
		return fmt.Errorf("object field type: %w", err)
	}
	return nil
}

// TypeInfo represents a type in the Shatter type system.
type TypeInfo struct {
	Kind        string                 `json:"kind"`
	Label       string                 `json:"label,omitempty"`        // opaque
	Element     *TypeInfo              `json:"element,omitempty"`      // array
	Fields      []ObjectField          `json:"fields,omitempty"`       // object
	Variants    []TypeInfo             `json:"variants,omitempty"`     // union
	Inner       *TypeInfo              `json:"inner,omitempty"`        // nullable, complex wrapper
	ComplexKind string                 `json:"complex_kind,omitempty"` // complex
	Metadata    map[string]interface{} `json:"metadata,omitempty"`     // complex
}

// ParamInfo describes a function parameter.
type ParamInfo struct {
	Name     string   `json:"name"`
	Type     TypeInfo `json:"type"`
	TypeName *string  `json:"type_name,omitempty"`
}

// LiteralValue is a literal constant found in a function body, used as a
// candidate test input. The JSON tags match the Rust core's
// #[serde(tag = "type", rename_all = "snake_case")] enum encoding.
type LiteralValue struct {
	Type    string `json:"type"`
	Value   any    `json:"value,omitempty"`   // int/float/str/bool literals
	Pattern string `json:"pattern,omitempty"` // regex literals only
}

// CryptoBoundary represents a detected cryptographic API boundary within a function.
// Populated by core after analysis; frontends leave this empty.
type CryptoBoundary struct {
	Symbol       string            `json:"symbol"`
	SourceModule string            `json:"source_module"`
	Direction    string            `json:"direction"`
	Output       string            `json:"output"`
	ParamRoles   map[string]string `json:"param_roles,omitempty"`
	CallSites    []int             `json:"call_sites"`
}

// FunctionAnalysis is the result of analyzing a single function.
type FunctionAnalysis struct {
	Name              string               `json:"name"`
	Exported          bool                 `json:"exported,omitempty"`
	Params            []ParamInfo          `json:"params"`
	Branches          []BranchInfo         `json:"branches"`
	Dependencies      []ExternalDependency `json:"dependencies"`
	ReturnType        TypeInfo             `json:"return_type"`
	StartLine         int                  `json:"start_line"`
	EndLine           int                  `json:"end_line"`
	Literals          []LiteralValue       `json:"literals,omitempty"`
	CryptoBoundaries  []CryptoBoundary     `json:"crypto_boundaries,omitempty"`
}

// BranchInfo describes a branch point in the source code.
type BranchInfo struct {
	ID            int      `json:"id"`
	Line          int      `json:"line"`
	ConditionText string   `json:"condition_text"`
	Condition     *SymExpr `json:"condition"`
	BranchType    string   `json:"branch_type"`
}

// BranchDecision records which way a branch was taken during execution.
type BranchDecision struct {
	BranchID   int            `json:"branch_id"`
	Line       int            `json:"line"`
	Taken      bool           `json:"taken"`
	Constraint *SymConstraint `json:"constraint"`
}

// SymExpr is a symbolic expression representing a constraint on inputs.
type SymExpr struct {
	Kind     string    `json:"kind"`
	Name     string    `json:"name,omitempty"`
	Path     []string  `json:"path"`
	Type     string    `json:"type,omitempty"`
	Value    any       `json:"value,omitempty"`
	Op       string    `json:"op,omitempty"`
	Left     *SymExpr  `json:"left,omitempty"`
	Right    *SymExpr  `json:"right,omitempty"`
	Operand  *SymExpr  `json:"operand,omitempty"`
	Receiver *SymExpr  `json:"receiver,omitempty"`
	Args     []SymExpr `json:"args,omitempty"`
}

// SymConstraint is either an expression constraint or an unknown hint.
type SymConstraint struct {
	Kind string   `json:"kind"`
	Expr *SymExpr `json:"expr,omitempty"`
	Hint string   `json:"hint,omitempty"`
}

// ExternalDependency describes a dependency on an external symbol.
type ExternalDependency struct {
	Kind         string     `json:"kind"`
	Symbol       string     `json:"symbol"`
	SourceModule string     `json:"source_module"`
	ReturnType   TypeInfo   `json:"return_type"`
	ParamTypes   []TypeInfo `json:"param_types"`
	CallSites    []int      `json:"call_sites"`
}

// ExternalCall records an observed call to an external dependency.
type ExternalCall struct {
	Symbol      string `json:"symbol"`
	Args        []any  `json:"args"`
	ReturnValue any    `json:"return_value"`
}

// MockConfig specifies how to mock an external dependency.
type MockConfig struct {
	Symbol           string `json:"symbol"`
	ReturnValues     []any  `json:"return_values"`
	ShouldTrackCalls bool   `json:"should_track_calls"`
	DefaultBehavior  string `json:"default_behavior"`
}

// ErrorInfo describes an error thrown during execution.
type ErrorInfo struct {
	ErrorType     string  `json:"error_type"`
	Message       string  `json:"message"`
	Stack         *string `json:"stack"`
	ErrorCategory *string `json:"error_category,omitempty"`
}

// TruncationInfo contains metadata about truncation applied to captured side effects.
type TruncationInfo struct {
	WasTruncated  bool   `json:"was_truncated"`
	OriginalLines uint32 `json:"original_lines"`
	OriginalBytes uint64 `json:"original_bytes"`
}

// SideEffect represents an observed side effect.
type SideEffect struct {
	Kind      string           `json:"kind"`
	Level     string           `json:"level,omitempty"`
	Message   string           `json:"message,omitempty"`
	Path      string           `json:"path,omitempty"`
	Content   string           `json:"content,omitempty"`
	Method    string           `json:"method,omitempty"`
	URL       string           `json:"url,omitempty"`
	Body      *json.RawMessage `json:"body,omitempty"`
	Name      string           `json:"name,omitempty"`
	ErrorType string           `json:"error_type,omitempty"`
	Stack     *string          `json:"stack,omitempty"`
	Variable  string           `json:"variable,omitempty"`
	Value     *string          `json:"value,omitempty"`
	Before    *json.RawMessage `json:"before,omitempty"`
	After     *json.RawMessage `json:"after,omitempty"`
}

// PerfMetrics captures execution performance data.
type PerfMetrics struct {
	WallTimeMs         float64 `json:"wall_time_ms"`
	CPUTimeUs          int     `json:"cpu_time_us"`
	HeapUsedBytes      int     `json:"heap_used_bytes"`
	HeapAllocatedBytes int     `json:"heap_allocated_bytes"`
}

package protocol

import (
	"bufio"
	"context"
	"encoding/json"
	"fmt"
	"io"
	"log/slog"
	"os"
	"strconv"
	"strings"

	"github.com/shatter-dev/shatter/shatter-go/generators"
	"github.com/shatter-dev/shatter/shatter-go/instrument"
	"github.com/shatter-dev/shatter/shatter-go/setup"
)

const frontendVersion = "0.1.0"
const frontendLanguage = "go"

// Handler processes protocol requests and writes responses.
type Handler struct {
	reader           *bufio.Scanner
	writer           io.Writer
	log              *slog.Logger
	lastAnalyzedFile string // remembered from the most recent analyze command
	registry         *generators.Registry
	setupLoader      *setup.Loader
}

// NewHandler creates a handler reading from r, writing responses to w,
// and logging to logw at the level set by SHATTER_LOG_LEVEL.
func NewHandler(r io.Reader, w io.Writer, logw io.Writer) *Handler {
	scanner := bufio.NewScanner(r)
	scanner.Buffer(make([]byte, 0, 1024*1024), 10*1024*1024) // 10MB max line
	return &Handler{
		reader:      scanner,
		writer:      w,
		log:         slog.New(newPrefixHandler(logw, slogLevelFromEnv())),
		registry:    generators.NewRegistry(),
		setupLoader: setup.NewLoader(),
	}
}

// NewHandlerWithLogLevel creates a handler with an explicit log level (for testing).
func NewHandlerWithLogLevel(r io.Reader, w io.Writer, logw io.Writer, level string) *Handler {
	scanner := bufio.NewScanner(r)
	scanner.Buffer(make([]byte, 0, 1024*1024), 10*1024*1024)
	return &Handler{
		reader:      scanner,
		writer:      w,
		log:         slog.New(newPrefixHandler(logw, slogLevelFromString(level))),
		registry:    generators.NewRegistry(),
		setupLoader: setup.NewLoader(),
	}
}

// Run processes requests until shutdown or EOF. Returns nil on clean shutdown.
func (h *Handler) Run() error {
	h.log.Debug("Starting Go frontend", "protocol", ProtocolVersion)

	for h.reader.Scan() {
		line := h.reader.Text()
		if line == "" {
			continue
		}

		h.log.Log(context.Background(), LevelTrace, "Received", "raw", line)

		var req Request
		if err := json.Unmarshal([]byte(line), &req); err != nil {
			h.log.Log(context.Background(), LevelTrace, "Failed to parse request", "err", err)
			errResp := Response{
				ProtocolVersion: ProtocolVersion,
				ID:              0,
				Status:          "error",
				Code:            ErrInvalidRequest,
				Message:         fmt.Sprintf("Invalid JSON: %s", err.Error()),
			}
			if sendErr := h.send(errResp); sendErr != nil {
				return fmt.Errorf("writing error response: %w", sendErr)
			}
			continue
		}

		resp, shutdown := h.dispatch(req)
		if err := h.send(resp); err != nil {
			return fmt.Errorf("writing response: %w", err)
		}

		if shutdown {
			h.log.Debug("Shutting down")
			return nil
		}
	}

	if err := h.reader.Err(); err != nil {
		return fmt.Errorf("reading stdin: %w", err)
	}

	h.log.Debug("Stdin closed, exiting")
	return nil
}

func (h *Handler) dispatch(req Request) (Response, bool) {
	base := Response{
		ProtocolVersion: ProtocolVersion,
		ID:              req.ID,
	}

	if !isVersionCompatible(req.ProtocolVersion) {
		base.Status = "error"
		base.Code = ErrVersionMismatch
		base.Message = fmt.Sprintf(
			"unsupported protocol version %q, expected %q",
			req.ProtocolVersion, ProtocolVersion,
		)
		return base, false
	}

	switch req.Command {
	case "handshake":
		return h.handleHandshake(base, req), false
	case "analyze":
		return h.handleAnalyze(base, req), false
	case "instrument":
		return h.handleInstrument(base, req), false
	case "execute":
		return h.handleExecute(base, req), false
	case "setup":
		return h.handleSetup(base, req), false
	case "teardown":
		return h.handleTeardown(base, req), false
	case "generate":
		return h.handleGenerate(base, req), false
	case "shutdown":
		return h.handleShutdown(base), true
	default:
		base.Status = "error"
		base.Code = ErrInvalidRequest
		base.Message = fmt.Sprintf("unknown command: %s", req.Command)
		return base, false
	}
}

func (h *Handler) handleHandshake(resp Response, req Request) Response {
	resp.Status = "handshake"
	resp.FrontendVersion = frontendVersion
	resp.Language = frontendLanguage
	caps := make([]string, len(CommandCapabilities))
	copy(caps, CommandCapabilities)
	caps = append(caps,
		"complex_type:date", "complex_type:duration", "complex_type:url",
		"complex_type:reg_exp", "complex_type:ip_address", "complex_type:big_int",
		"complex_type:rational", "complex_type:big_decimal", "complex_type:error",
	)
	resp.Capabilities = caps
	return resp
}

func (h *Handler) handleAnalyze(resp Response, req Request) Response {
	if req.File == "" {
		resp.Status = "error"
		resp.Code = ErrInvalidRequest
		resp.Message = "analyze command requires a file path"
		return resp
	}

	if _, err := os.Stat(req.File); err != nil {
		resp.Status = "error"
		resp.Code = ErrFileNotFound
		resp.Message = fmt.Sprintf("file not found: %s", req.File)
		return resp
	}

	h.lastAnalyzedFile = req.File

	var functionName string
	if req.Function != nil {
		functionName = *req.Function
	}

	functions, err := AnalyzeFile(req.File, functionName)
	if err != nil {
		if functionName != "" && isNotFound(err) {
			resp.Status = "error"
			resp.Code = ErrFunctionNotFound
			resp.Message = fmt.Sprintf("function %q not found in %s", functionName, req.File)
			return resp
		}
		resp.Status = "error"
		resp.Code = ErrParseError
		resp.Message = err.Error()
		return resp
	}

	resp.Status = "analyze"
	if functions == nil {
		functions = []FunctionAnalysis{}
	}
	resp.Functions = functions
	return resp
}

func isNotFound(err error) bool {
	return err != nil && strings.HasPrefix(err.Error(), "function not found")
}

func (h *Handler) handleInstrument(resp Response, req Request) Response {
	if req.File == "" {
		resp.Status = "error"
		resp.Code = ErrInvalidRequest
		resp.Message = "instrument command requires a file path"
		return resp
	}

	if _, err := os.Stat(req.File); err != nil {
		resp.Status = "error"
		resp.Code = ErrFileNotFound
		resp.Message = fmt.Sprintf("file not found: %s", req.File)
		return resp
	}

	h.lastAnalyzedFile = req.File

	outputDir, err := instrument.InstrumentFile(req.File, req.Function, req.ProjectRoot)
	if err != nil {
		resp.Status = "error"
		resp.Code = ErrInternalError
		resp.Message = fmt.Sprintf("instrumentation failed: %v", err)
		return resp
	}

	instrumented := true
	resp.Status = "instrument"
	resp.Instrumented = &instrumented
	resp.OutputFile = &outputDir
	return resp
}

func (h *Handler) handleExecute(resp Response, req Request) Response {
	file := req.File
	if file == "" {
		file = h.lastAnalyzedFile
	}
	if file == "" {
		resp.Status = "error"
		resp.Code = ErrInvalidRequest
		resp.Message = "execute command requires a file path (or a prior analyze)"
		return resp
	}

	if req.Function == nil || *req.Function == "" {
		resp.Status = "error"
		resp.Code = ErrInvalidRequest
		resp.Message = "execute command requires a function name"
		return resp
	}

	if _, err := os.Stat(file); err != nil {
		resp.Status = "error"
		resp.Code = ErrFileNotFound
		resp.Message = fmt.Sprintf("file not found: %s", file)
		return resp
	}

	// Convert protocol MockConfigs to instrument MockConfigs and pass to executor.
	var execMocks []instrument.MockConfig
	for _, m := range req.Mocks {
		execMocks = append(execMocks, instrument.MockConfig{
			Symbol:           m.Symbol,
			ReturnValues:     m.ReturnValues,
			ShouldTrackCalls: m.ShouldTrackCalls,
			DefaultBehavior:  m.DefaultBehavior,
		})
	}
	result, err := instrument.ExecuteFunction(file, *req.Function, req.Inputs, execMocks)
	if err != nil {
		resp.Status = "error"
		if strings.Contains(err.Error(), "function not found") {
			resp.Code = ErrFunctionNotFound
		} else if strings.Contains(err.Error(), "build failed") {
			resp.Code = ErrInstrumentationFailed
		} else if strings.Contains(err.Error(), "timed out") {
			resp.Code = ErrExecutionTimeout
		} else {
			resp.Code = ErrInternalError
		}
		resp.Message = err.Error()
		return resp
	}

	resp.Status = "execute"
	resp.ReturnValue = result.ReturnValue
	resp.ThrownError = convertErrorInfo(result.ThrownError)
	resp.LinesExecuted = toIntSlice(result.LinesExecuted)
	resp.BranchPath = convertBranchPath(result.BranchPath)
	resp.PathConstraints = extractPathConstraints(result.BranchPath)
	resp.CallsToExternal = convertExternalCalls(result.ExternalCalls)
	resp.SideEffects = convertSideEffects(result.SideEffects)
	resp.ScopeEvents = result.ScopeEvents
	resp.Performance = &PerfMetrics{
		WallTimeMs:         result.Performance.WallTimeMs,
		CPUTimeUs:          result.Performance.CPUTimeUs,
		HeapUsedBytes:      result.Performance.HeapUsedBytes,
		HeapAllocatedBytes: result.Performance.HeapAllocatedBytes,
	}

	return resp
}

func convertErrorInfo(e *instrument.ErrorInfo) *ErrorInfo {
	if e == nil {
		return nil
	}
	var stack *string
	if e.Stack != "" {
		stack = &e.Stack
	}
	return &ErrorInfo{
		ErrorType: e.ErrorType,
		Message:   e.Message,
		Stack:     stack,
	}
}

func toIntSlice(ints []int) []int {
	if ints == nil {
		return []int{}
	}
	return ints
}

func convertBranchPath(branches []instrument.BranchDecision) []BranchDecision {
	result := make([]BranchDecision, len(branches))
	for i, b := range branches {
		constraint := &SymConstraint{Kind: "unknown", Hint: "no symbolic constraint from Go frontend"}
		if b.ConstraintJSON != "" {
			var sc SymConstraint
			if err := json.Unmarshal([]byte(b.ConstraintJSON), &sc); err == nil {
				constraint = &sc
			}
		}
		result[i] = BranchDecision{
			BranchID:   b.BranchID,
			Line:       b.Line,
			Taken:      b.Taken,
			Constraint: constraint,
		}
	}
	return result
}

func extractPathConstraints(branches []instrument.BranchDecision) []SymConstraint {
	var constraints []SymConstraint
	for _, b := range branches {
		if b.ConstraintJSON == "" {
			continue
		}
		var sc SymConstraint
		if err := json.Unmarshal([]byte(b.ConstraintJSON), &sc); err == nil {
			constraints = append(constraints, sc)
		}
	}
	if constraints == nil {
		return []SymConstraint{}
	}
	return constraints
}

// convertExternalCalls converts executor ExternalCall records to protocol format.
func convertExternalCalls(calls []instrument.ExternalCall) []ExternalCall {
	if len(calls) == 0 {
		return []ExternalCall{}
	}
	result := make([]ExternalCall, len(calls))
	for i, c := range calls {
		var args []any
		if c.Args != nil {
			json.Unmarshal(c.Args, &args) //nolint:errcheck
		}
		var retVal any
		if c.ReturnValue != nil {
			json.Unmarshal(c.ReturnValue, &retVal) //nolint:errcheck
		}
		result[i] = ExternalCall{
			Symbol:      c.Symbol,
			Args:        args,
			ReturnValue: retVal,
		}
	}
	return result
}

// convertSideEffects converts executor SideEffects to protocol format.
func convertSideEffects(effects []instrument.SideEffect) []SideEffect {
	if len(effects) == 0 {
		return []SideEffect{}
	}
	result := make([]SideEffect, len(effects))
	for i, e := range effects {
		result[i] = SideEffect{
			Kind:    e.Kind,
			Level:   e.Level,
			Message: e.Message,
		}
	}
	return result
}

func (h *Handler) handleSetup(resp Response, req Request) Response {
	if req.File == "" {
		resp.Status = "error"
		resp.Code = ErrInvalidRequest
		resp.Message = "setup command requires a file path"
		return resp
	}
	if req.Scope == "" {
		resp.Status = "error"
		resp.Code = ErrInvalidRequest
		resp.Message = "setup command requires a scope"
		return resp
	}
	if !req.Level.IsValid() {
		resp.Status = "error"
		resp.Code = ErrInvalidRequest
		resp.Message = fmt.Sprintf("setup command requires a valid level, got %q", req.Level)
		return resp
	}

	if _, err := os.Stat(req.File); err != nil {
		resp.Status = "error"
		resp.Code = ErrFileNotFound
		resp.Message = fmt.Sprintf("setup file not found: %s", req.File)
		return resp
	}

	var parentCtxJSON json.RawMessage
	if req.ParentContext != nil {
		data, err := json.Marshal(req.ParentContext)
		if err != nil {
			resp.Status = "error"
			resp.Code = ErrInternalError
			resp.Message = fmt.Sprintf("marshaling parent context: %v", err)
			return resp
		}
		parentCtxJSON = data
	}

	h.log.Debug("Running setup", "file", req.File, "scope", req.Scope, "level", req.Level)

	ctx, err := h.setupLoader.RunSetup(req.File, req.Scope, string(req.Level), req.ProjectRoot, parentCtxJSON)
	if err != nil {
		resp.Status = "error"
		resp.Code = ErrInternalError
		resp.Message = fmt.Sprintf("setup failed: %v", err)
		return resp
	}

	resp.Status = "setup"
	ctxCopy := json.RawMessage(ctx)
	resp.SetupContext = &ctxCopy
	return resp
}

func (h *Handler) handleTeardown(resp Response, req Request) Response {
	if req.Scope == "" {
		resp.Status = "error"
		resp.Code = ErrInvalidRequest
		resp.Message = "teardown command requires a scope"
		return resp
	}
	if !req.Level.IsValid() {
		resp.Status = "error"
		resp.Code = ErrInvalidRequest
		resp.Message = fmt.Sprintf("teardown command requires a valid level, got %q", req.Level)
		return resp
	}

	h.log.Debug("Running teardown", "scope", req.Scope, "level", req.Level)

	found := h.setupLoader.Teardown(req.Scope, string(req.Level))
	if !found {
		resp.Status = "error"
		resp.Code = ErrInternalError
		resp.Message = fmt.Sprintf("No setup context found for %s:%s. Call setup first.", req.Level, req.Scope)
		return resp
	}

	// Clear stale session state so the next setup/execute cycle starts clean.
	h.lastAnalyzedFile = ""
	h.registry.Handles.Clear()

	resp.Status = "teardown_ack"
	return resp
}

func (h *Handler) handleGenerate(resp Response, req Request) Response {
	if req.File == "" {
		resp.Status = "error"
		resp.Code = ErrInvalidRequest
		resp.Message = "generate command requires a file path"
		return resp
	}
	if req.Name == "" {
		resp.Status = "error"
		resp.Code = ErrInvalidRequest
		resp.Message = "generate command requires a name"
		return resp
	}

	var recipe json.RawMessage
	if req.Recipe != nil {
		recipe = *req.Recipe
	}

	value, generatorID, outRecipe, err := h.registry.Generate(req.File, req.Name, recipe)
	if err != nil {
		resp.Status = "error"
		resp.Code = ErrInternalError
		resp.Message = fmt.Sprintf("generate failed: %v", err)
		return resp
	}

	resp.Status = "generate"
	valCopy := json.RawMessage(value)
	resp.Value = &valCopy
	resp.GeneratorID = generatorID
	if outRecipe != nil {
		recipeCopy := json.RawMessage(outRecipe)
		resp.Recipe = &recipeCopy
	}
	return resp
}

// Registry returns the generator registry, allowing custom builds to register
// native generators before calling Run().
func (h *Handler) Registry() *generators.Registry {
	return h.registry
}

func (h *Handler) handleShutdown(resp Response) Response {
	h.registry.Close()
	h.setupLoader.Close()
	resp.Status = "shutdown_ack"
	return resp
}

// parseMajorMinor extracts the major and minor components from a semver string.
// Returns (major, minor, ok). ok is false if the version string is malformed.
func parseMajorMinor(version string) (int, int, bool) {
	parts := strings.SplitN(version, ".", 3)
	if len(parts) < 2 {
		return 0, 0, false
	}
	major, err := strconv.Atoi(parts[0])
	if err != nil {
		return 0, 0, false
	}
	minor, err := strconv.Atoi(parts[1])
	if err != nil {
		return 0, 0, false
	}
	return major, minor, true
}

// isVersionCompatible checks whether a requested protocol version is compatible
// with ProtocolVersion by comparing major and minor components (patch is ignored).
// Matches the TypeScript frontend's semver-compatible behavior.
func isVersionCompatible(version string) bool {
	reqMajor, reqMinor, reqOK := parseMajorMinor(version)
	ourMajor, ourMinor, ourOK := parseMajorMinor(ProtocolVersion)
	if !reqOK || !ourOK {
		return false
	}
	return reqMajor == ourMajor && reqMinor == ourMinor
}

func (h *Handler) send(resp Response) error {
	data, err := json.Marshal(resp)
	if err != nil {
		return fmt.Errorf("marshaling response: %w", err)
	}
	line := string(data) + "\n"
	h.log.Log(context.Background(), LevelTrace, "Sent", "raw", string(data))
	_, err = io.WriteString(h.writer, line)
	return err
}

